INSERT INTO Project VALUES('cmrby3y0000001znnofoo0a53','추노','장소와 관계없이 실시간 GPS 기반으로 러닝 거리를 경쟁하는 모바일 앱 (Android/iOS). 방을 만들어 참가자들이 목표 거리를 먼저 완주한 순서로 등수를 겨룬다.','/Users/jeangho293/vscode/chuno-run',1783507152096,1783507152096);
CREATE TABLE IF NOT EXISTS "Plan" (
    "id" TEXT NOT NULL PRIMARY KEY,
    "projectId" TEXT NOT NULL,
    "title" TEXT NOT NULL,
    "content" TEXT NOT NULL,
    "status" TEXT NOT NULL DEFAULT 'draft',
    "version" INTEGER NOT NULL DEFAULT 1,
    "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updatedAt" DATETIME NOT NULL,
    CONSTRAINT "Plan_projectId_fkey" FOREIGN KEY ("projectId") REFERENCES "Project" ("id") ON DELETE CASCADE ON UPDATE CASCADE
);
INSERT INTO "Plan" VALUES('cmrby4wah00021znnga9fbhfq','cmrby3y0000001znnofoo0a53','1차 MVP 기획서',unistr('# 추노\u000a\u000a## 1. 개요 / 목적\u000a\u000a> 🎯 **목적** — 장소에 상관없이, 실시간 GPS로 각자 뛰면서 "누가 목표 거리에 먼저 도달하는가"를 겨루는 경쟁 러닝 앱.\u000a\u000a같은 트랙에 모이지 않아도 방 하나로 원격 러닝 대결이 성립한다. 러닝을 습관화하고 싶지만 동기부여가 부족한 사람에게 "혼자 뛰어도 함께 경쟁하는" 경험을 제공한다. 1차 MVP는 Android/iOS 두 플랫폼을 Flutter 단일 코드베이스로 동시 지원하며, 소셜 로그인 → **최초 온보딩(약관 동의·프로필 설정)** → 방 생성 → 대기 → 실시간 경주 → 등수 판정 → 결과의 한 사이클을 안정적으로 완주시키는 것을 목표로 한다. 위치 정보를 상시 수집하는 서비스 특성상, 최초 가입 시 개인정보·위치기반서비스 약관 동의를 필수로 받는다.\u000a\u000a## 2. 타깃 사용자 & 유스케이스\u000a\u000a| 페르소나 | 니즈 | 핵심 유스케이스 |\u000a| --- | --- | --- |\u000a| 동기부여가 필요한 러너 | 혼자 뛰면 지루하고 꾸준하지 못함 | 친구와 방을 만들어 목표 거리 대결, 이겨서 성취감을 얻는다 |\u000a| 원격의 지인 그룹 | 서로 다른 지역에 살아 같이 못 뜀 | 각자 동네에서 같은 방에 입장해 동시에 스타트, 실시간 순위를 본다 |\u000a| 가벼운 경쟁을 즐기는 사람 | 기록 경쟁·게임성 | 짧은 거리(예: 3km) 방에 참여해 빠르게 승부를 낸다 |\u000a| 신규 가입자 | 안심하고 서비스를 시작하고 싶음 | 최초 로그인 후 약관·개인정보 동의와 닉네임 설정을 마치고 서비스에 진입한다 |\u000a\u000a## 3. 핵심 기능 (MVP)\u000a\u000a| 우선순위 | 기능 | 설명 |\u000a| --- | --- | --- |\u000a| 높음 | 소셜 로그인 | 카카오 / 구글 / 애플 인증으로 가입·로그인 (자체 이메일 가입 없음) |\u000a| 높음 | 온보딩 & 약관 동의 | 최초 가입 시 필수 약관(서비스 이용약관·개인정보 수집·이용·위치기반서비스 이용약관) 동의, 닉네임 설정. 선택 약관(마케팅 수신)은 건너뛰기 가능. 필수 미동의 시 진입 차단 |\u000a| 높음 | 약관 버전 관리·개정 재동의 | 약관은 버전 단위로 관리한다. 필수 약관이 개정되면 재로그인 시 변경된 약관만 재동의 요구 |\u000a| 높음 | 방 생성 | 목표 거리·제한 시간·시작 시간·최대 인원을 설정해 방 개설 |\u000a| 높음 | 방 목록 / 입장 | 모집 중 상태의 방에만 입장 가능. 지각 입장 없음 |\u000a| 높음 | 대기실 & 방장 관리 | 현 인원/정원·참가자 목록·시작 카운트다운·완주 기준 페이스 표시. 모집 중 방장이 목표 거리·제한 시간·최대 인원 수정 및 참가자 강퇴 가능 |\u000a| 높음 | 자동 모집 마감·취소 | 시작 10분 전 모집 마감. 이 시점에 참가자 2명 미만이면 경주 자동 취소 |\u000a| 높음 | 실시간 GPS 러닝 | 디바이스 GPS로 이동 거리 누적, WebSocket으로 참가자 위치/거리 실시간 동기화 |\u000a| 높음 | 실시간 리더보드 | 경주 중 참가자 순위·거리·페이스를 실시간 표시 |\u000a| 높음 | 등수 판정 | 클라이언트 GPS 기반으로 목표 도달 순서에 따라 등수 확정. 동시 도달 시 공동 순위. 미완주·중도 이탈자는 완주자 뒤 누적 거리순 |\u000a| 보통 | 결과 & 경주 이력 | 경주 종료 후 사용자별 경주 이력에서 결과(등수·거리·시간·페이스) 조회 |\u000a\u000a> 📌 **참고** — 방(Room)의 상태와 전이 규칙은 도메인 문서(`/ib-domain`)에서 정의한다. 약관 동의는 **Agreement(약관 마스터: 유형·버전·필수 여부·본문)** 와 **UserConsent(사용자별 동의 이력: 약관·동의 여부·동의 시각)** 도메인으로 관리한다 (정의 완료).\u000a\u000a## 4. 범위 밖 (Out of Scope)\u000a\u000a> ⚠️ **범위 밖** — 이번 1차 MVP에서 하지 않는다.\u000a> - 약관 원문(법무 문안) 작성 자체 — 법무/운영 영역, 기획은 동의 흐름·데이터만 다룸\u000a> - 만 14세 미만 연령 확인·법정대리인 동의 — 이번 MVP에서 제외\u000a> - 소셜 기능 (친구, 팔로우, 채팅)\u000a> - 랭킹/리그/시즌, 리워드·포인트\u000a> - 코스 지정형(특정 경로 완주), 팀전\u000a> - 웨어러블(스마트워치) 연동\u000a> - 자체 이메일/비밀번호 회원가입\u000a\u000a> ➡️ **2차 이관** — 아래 항목은 「2차 MVP 기획서」로 옮겼다: 푸시 알림 · 멀티기기 지원 · 경주 중 지도/경로 표시 · 진행 중 경주 복귀 · 서버 측 목표 도달 재검증 · 부정행위 방지(GPS 스푸핑·차량 이동 탐지) · GPS 튐 보정 · 개인정보 관리 화면(동의 철회·다운로드).\u000a\u000a## 5. 비기능 요구사항\u000a\u000a| 항목 | 요구사항/기준 |\u000a| --- | --- |\u000a| 플랫폼 | Flutter 단일 코드베이스로 Android / iOS 동시 지원 |\u000a| 실시간성 | 리더보드/위치 동기화 지연 수 초 이내 (WebSocket) |\u000a| 개인정보/약관 | 필수 약관 동의 없이는 서비스 이용 불가. 동의 이력(약관 유형·버전·동의 시각)을 보관하고 개인정보보호법·위치정보법을 준수 |\u000a| 위치 권한 | 위치 권한(백그라운드 포함)은 필수. 거부 시 앱 사용 불가 처리 |\u000a| 위치 정확도 | GPS 이동 거리 오차 허용 범위 내, 백그라운드 위치 추적 지원 |\u000a| 안정성 | 방 생성 → 경주 완료까지 크래시 없이 완주 가능 |\u000a| 복원력 | 러닝 중 네트워크 단절 시 재연결·거리 재동기화 처리 |\u000a| 인증/보안 | OAuth 기반 소셜 로그인 (카카오/구글/애플) |\u000a| 배터리 | 지속 GPS 추적에도 실사용 가능한 배터리 소모 수준 |\u000a\u000a## 6. 성공 지표\u000a\u000a| 지표 | 목표값 | 측정 방법 |\u000a| --- | --- | --- |\u000a| 온보딩 완료율 | 로그인 사용자의 90% 이상이 약관 동의·닉네임 설정까지 완료 | 온보딩 단계별 이벤트 로그 |\u000a| 경주 완주율 | 시작한 경주의 95% 이상 크래시 없이 결과 도달 | 세션 로그/크래시 리포트 |\u000a| 리더보드 동기화 지연 | 평균 3초 이내 | 서버-클라이언트 타임스탬프 비교 |\u000a| 거리 측정 오차 | 실측 대비 ±5% 이내 | 기준 코스 실측 테스트 |\u000a| 리텐션(참고) | 첫 경주 후 재참여율 측정 | 사용자별 경주 참여 이벤트 |\u000a\u000a## 7. 테스트 시나리오\u000a\u000a| # | 시나리오 | 절차 (핵심 흐름) | 기대 결과 |\u000a| --- | --- | --- | --- |\u000a| 1 | 소셜 로그인 | 앱 실행 → 카카오/구글/애플 중 선택 → 인증 | 로그인 성공 |\u000a| 2 | 최초 온보딩 | 최초 로그인 → 필수 약관 전체 동의 + 닉네임 입력 → 완료 | 홈 진입, 동의 이력 저장 |\u000a| 3 | 필수 약관 미동의 | 온보딩에서 필수 약관 일부 미동의 상태로 진행 시도 | 진행 버튼 비활성/차단, 진입 불가 |\u000a| 4 | 재로그인 스킵 | 이미 온보딩 완료한 사용자가 재로그인 | 온보딩 생략, 곧바로 홈 |\u000a| 5 | 약관 개정 재동의 | 필수 약관 개정(새 버전) 후 기존 사용자 로그인 | 변경된 약관만 재동의 화면 노출, 동의 후 진입 |\u000a| 6 | 방 생성·입장 | 홈 → 방 생성(거리·시간·정원 입력) → 다른 사용자 입장 | 대기실에 현 인원/정원·참가자 반영, 모집 중 상태 |\u000a| 7 | 방장 조건 수정·강퇴 | 모집 중 방장이 목표 거리 변경, 참가자 강퇴 | 변경 즉시 반영(페이스 재계산), 강퇴된 사용자 방에서 제거 |\u000a| 8 | 지각 입장 차단 | 모집 마감/경기 중 방에 입장 시도 | 입장 거부 |\u000a| 9 | 자동 취소 | 시작 10분 전(모집 마감) 참가자 1명 | 경주 취소, 참가자에 취소 안내 |\u000a| 10 | 동시 스타트 | 2명 이상 유지 → 시작 시간 도달 | 경기 시작, 참가자 전원 동시 스타트 |\u000a| 11 | 실시간 경주 | 각자 러닝 → 거리 누적 전송 | 리더보드에 실시간 순위·거리 갱신 |\u000a| 12 | 등수 판정 (공동 순위) | 참가자들이 목표 거리 도달, 일부 동시 도달 | 도달 순 등수 확정, 동시 도달자는 공동 순위 |\u000a| 13 | 제한 시간 만료·이탈 | 목표 미도달 또는 중도 이탈 상태로 종료 | 완주자 뒤로 누적 거리순 정렬, 경주 종료 |\u000a| 14 | 경주 이력 확인 | 종료 후 사용자 경주 이력 진입 | 최종 등수·개인 기록(거리/시간/페이스) 표시 |\u000a| 15 | 위치 권한 거부 | 위치 권한 거부/미허용 | 앱 사용 불가 안내 화면 |\u000a\u000a## 8. 핵심 가정 / 미결 질문\u000a\u000a> ✅ **확정** — 약관 구성: 필수 = 서비스 이용약관 · 개인정보 수집·이용 동의 · 위치기반서비스 이용약관 / 선택 = 마케팅 정보 수신. (만 14세 이상 확인 제외) · 약관은 **버전 단위로 관리**하고, 개정 시 **변경된 약관만 재동의**. 관련 도메인(Agreement / UserConsent) 정의 완료.\u000a\u000a> 📝 **가정 / 미결** — 확정 안 된 사항 및 의도적 단순화. 착수 전 인지 필요.\u000a> - **약관 원문 확보(미결)**: 실제 약관 문안은 법무 검토 필요 — 기획은 흐름/데이터만 정의.\u000a> - **클라이언트 판정의 신뢰성(의도적 단순화)**: MVP는 목표 도달을 클라이언트 GPS 계산으로 판정하고 GPS 튐도 무시한다. 서버 검증·부정행위 방지·GPS 보정은 2차에서 보완.\u000a> - **백엔드 스택 미정**: 서버 언어/프레임워크, WebSocket 서버, DB 선정 필요.\u000a> - **거리 측정 방식**: 순수 GPS 누적 vs 스텝/센서 융합 — 정확도/배터리 트레이드오프.\u000a> - **동시 시작 정합성**: startTime 기준 클라이언트 시계 오차 보정 방식.\u000a> - **백그라운드 추적 정책**: iOS/Android 백그라운드 위치 권한·배터리 정책 대응.\u000a> - **가정**: 애플 로그인 포함으로 iOS 소셜 로그인 심사 요건(Sign in with Apple 병행 제공) 충족.\u000a\u000a---\u000a### 진행 메모 (2026-07-09) — 1차 확정 스코프\u000a\u000a**입장 / 재동의**\u000a- 방 입장은 **공개 방 목록 입장 전용** (초대 코드·비공개 방 없음 — Room에 inviteCode 미도입).\u000a- 약관 **개정 재동의는 프로필 화면**에서 처리 (온보딩과 별도). `data-screen=profile`, `[Onboarding] 약관 버전 관리·재동의` 이슈를 profile에 연동.\u000a\u000a**경주 실행 (에픽 A~D)**\u000a- **판정 = 서버 릴레이(클라이언트 판정)**: 각 클라이언트가 GPS로 거리·목표 도달을 계산해 전송, 서버는 재계산 없이 도달/진행 순서만 확정. **원시 GPS 좌표 미보존**(TrackPoint 미도입) — 진행값은 `Participant.currentDistance`로만 전송.\u000a- **동시 스타트 = 서버 시각 기준**: 서버가 "start at T / ends at T+limit" 신호를 WS로 브로드캐스트, 클라이언트는 서버 시각 오프셋으로 카운트다운·종료.\u000a- **미완주·중도 이탈·앱 강제 종료 = dnf** → 완주자 뒤 누적 거리순.\u000a- **단일 기기 전제**(멀티기기 미지원), **푸시 알림 없음** → 대기실에서 앱을 열어둔 채 카운트다운하는 흐름을 전제로 한다.\u000a\u000a**2차로 이관됨** (→ 「2차 MVP 기획서」): 푸시 알림 · 멀티기기 지원 · 경주 중 지도/경로 표시(TrackPoint 재도입) · 진행 중 경주 복귀 · 서버 측 목표 도달 재검증 · 부정행위 방지 · GPS 튐 보정 · 개인정보 관리 화면.'),'approved',13,1783507196537,1783559930744);
INSERT INTO "Plan" VALUES('cmrcstk4t0015rwt4x4tn1p3s','cmrby3y0000001znnofoo0a53','2차 MVP 기획서',unistr('# 추노 — 2차 MVP\u000a\u000a## 1. 개요 / 목적\u000a\u000a> 🎯 **목적** — 1차 MVP에서 "한 사이클 완주"를 위해 의도적으로 미뤄둔 항목들을 채워, **여러 기기에서·앱을 닫아둔 채로도 경주가 매끄럽게 성립하고, 결과를 신뢰할 수 있는** 서비스로 끌어올린다.\u000a\u000a1차 MVP는 소셜 로그인 → 온보딩 → 방 → 실시간 경주 → 등수 → 결과의 한 사이클을 단일 기기·앱 포그라운드·클라이언트 판정 전제로 완주시키는 데 집중했다. 2차는 그 전제에서 생긴 UX·신뢰성 공백을 메운다: **푸시 알림**으로 예약 스타트를 앱을 닫아둔 채로도 놓치지 않게 하고, **멀티기기**를 지원하며, **진행 중 경주 복귀**로 러닝 도중 앱이 죽어도 이어달릴 수 있게 하고, **서버 재검증·부정행위 방지·GPS 보정**으로 결과의 공정성을 높인다. 여력에 따라 **경주 중 지도·경로 표시**와 **개인정보 관리 화면**을 더한다.\u000a\u000a## 2. 타깃 사용자 & 유스케이스\u000a\u000a| 페르소나 | 니즈 | 핵심 유스케이스 |\u000a| --- | --- | --- |\u000a| 예약 경주 참가자 | 시작 시각까지 앱을 계속 켜두기 번거로움 | 방 예약 후 앱을 닫아둬도 시작 임박·시작 푸시를 받고 제때 합류한다 |\u000a| 여러 기기 사용자 | 폰 교체·태블릿 병행 | 새 기기에서 로그인해도 동일 계정으로 이어 쓰고, 알림은 현재 쓰는 기기로 온다 |\u000a| 장거리 러너 | 러닝 중 앱이 죽으면 기록이 날아갈까 불안 | 앱이 강제 종료돼도 재실행하면 진행 중 경주로 자동 복귀해 이어 달린다 |\u000a| 공정성을 중시하는 경쟁자 | 치팅·GPS 튐으로 순위가 왜곡되는 게 싫음 | 서버가 도달을 재검증하고 이상 이동을 걸러 신뢰할 수 있는 등수를 받는다 |\u000a| 개인정보 민감 사용자 | 동의 철회·내 데이터 관리를 원함 | 설정에서 약관 동의를 철회하거나 내 데이터를 내려받는다 |\u000a\u000a## 3. 핵심 기능 (2차)\u000a\u000a| 우선순위 | 기능 | 설명 |\u000a| --- | --- | --- |\u000a| 높음 | 푸시 알림 | 시작 임박(모집 마감=시작 10분 전) / 시작(live) / 종료(finished) 3종 푸시. 예약 스타트를 앱을 닫아둔 채로도 놓치지 않게 한다. FCM/APNs 연동 |\u000a| 높음 | 멀티기기 지원 | 사용자 1명이 여러 기기에서 로그인·사용. 기기별 세션과 **기기별 푸시 토큰** 관리(로그인/권한 시 등록·갱신, 로그아웃 시 해지) |\u000a| 보통 | 진행 중 경주 복귀 | 앱 강제 종료 후 재실행 시 진행 중인 경주로 자동 복귀. 로컬 저장(마지막 누적 거리·경주 식별자)+서버 재동기화 |\u000a| 보통 | 서버 측 목표 도달 재검증 | 클라이언트 판정을 서버가 재검증(전송 거리·페이스·타임스탬프 정합성)해 등수 신뢰도를 높인다 |\u000a| 보통 | 부정행위 방지 | GPS 스푸핑·비정상 속도(차량 이동 등) 탐지 및 처리(경고·기록 무효). MVP는 클라 판정이라 열려 있던 부분 |\u000a| 보통 | GPS 튐 보정 | 순간 거리 급증(정확도 낮은 포인트) 필터링·스무딩으로 거리 오차를 줄인다 |\u000a| 보통 | 개인정보 관리 화면 | 약관 동의 철회, 내 데이터 다운로드/삭제 요청 등 개인정보 관리 진입점(개인정보보호법 대응 강화) |\u000a| 낮음 | 경주 중 지도·경로 표시 | 러닝 화면에 본인 경로/지도를 표시. 이를 위해 GPS 좌표 보존(TrackPoint 재도입) |\u000a\u000a## 4. 범위 밖 (Out of Scope)\u000a\u000a> ⚠️ **범위 밖** — 2차에서도 하지 않는다 (3차 이후 검토).\u000a> - 소셜 기능 (친구·팔로우·채팅)\u000a> - 랭킹/리그/시즌, 리워드·포인트\u000a> - 코스 지정형(특정 경로 완주), 팀전\u000a> - 웨어러블(스마트워치) 연동\u000a> - 자체 이메일/비밀번호 회원가입\u000a> - 만 14세 미만 연령 확인·법정대리인 동의\u000a\u000a## 5. 비기능 요구사항\u000a\u000a| 항목 | 요구사항/기준 |\u000a| --- | --- |\u000a| 알림 | 푸시 발송 지연 수십 초 이내, 미수신 시 앱 진입 시 상태 동기화로 보완 |\u000a| 멀티기기 | 기기별 토큰 유일성 관리, 로그아웃/기기 해지 시 해당 토큰으로 발송 중단 |\u000a| 복원력 | 앱 강제 종료·네트워크 단절 후에도 진행 중 경주 상태 복구, 로컬-서버 거리 정합 |\u000a| 판정 신뢰성 | 서버 재검증으로 클라이언트 조작·이상치의 순위 반영 최소화 |\u000a| 위치 정확도 | GPS 튐 보정 적용 후 거리 오차 실측 대비 ±3% 이내(1차 ±5%에서 강화) |\u000a| 개인정보 | 동의 철회·데이터 열람/삭제 요청 처리 흐름 및 이력 보관 |\u000a| 플랫폼 | 1차와 동일하게 Flutter 단일 코드베이스로 Android/iOS 동시 지원 |\u000a\u000a## 6. 성공 지표\u000a\u000a| 지표 | 목표값 | 측정 방법 |\u000a| --- | --- | --- |\u000a| 예약→시작 합류율 | 예약자의 85% 이상이 시작 시각에 경주 합류 | 푸시 발송/오픈·경주 합류 이벤트 |\u000a| 푸시 오픈율 | 시작 임박 푸시 오픈율 50% 이상 | 푸시 오픈 이벤트 |\u000a| 경주 복귀 성공률 | 러닝 중 앱 종료 케이스의 90% 이상 정상 복귀 | 복귀 시도/성공 로그 |\u000a| 판정 이의 감소 | 부정·오측 관련 이슈 리포트 1차 대비 50% 감소 | 신고/문의 집계 |\u000a| 거리 측정 오차 | 실측 대비 ±3% 이내 | 기준 코스 실측 테스트 |\u000a\u000a## 7. 테스트 시나리오\u000a\u000a| # | 시나리오 | 절차 (핵심 흐름) | 기대 결과 |\u000a| --- | --- | --- | --- |\u000a| 1 | 시작 임박 푸시 | 방 예약 → 앱 백그라운드/종료 → 시작 10분 전 도달 | 시작 임박 푸시 수신, 탭 시 대기실 진입 |\u000a| 2 | 시작/종료 푸시 | 경주 시작(live)·종료(finished) 시점 도달 | 각 시점 푸시 수신 |\u000a| 3 | 멀티기기 로그인 | 기기 A 로그인 사용 → 기기 B 로그인 | 두 기기 동일 계정, 각 기기 토큰 등록 |\u000a| 4 | 기기 해지 알림 중단 | 기기 A 로그아웃 | A 토큰 해지, 이후 알림 A로 미발송 |\u000a| 5 | 경주 복귀 | 러닝 중 앱 강제 종료 → 재실행 | 진행 중 경주로 자동 복귀, 누적 거리 재동기화 |\u000a| 6 | 서버 재검증 | 클라가 비정상 거리 급증 전송 | 서버가 이상치 반려/보정, 순위 미반영 |\u000a| 7 | 부정행위 탐지 | GPS 스푸핑·차량 속도 패턴 주입 | 탐지·경고 또는 기록 무효 처리 |\u000a| 8 | GPS 튐 보정 | 정확도 낮은 튐 포인트 포함 러닝 | 보정 후 거리 오차 ±3% 이내 |\u000a| 9 | 지도·경로 표시 | 러닝 중 지도 화면 진입 | 본인 경로 실시간 표시(TrackPoint 기반) |\u000a| 10 | 동의 철회 | 개인정보 관리 화면에서 동의 철회 | 철회 처리·이력 저장, 정책상 후속 안내 |\u000a\u000a## 8. 핵심 가정 / 미결 질문\u000a\u000a> 📝 **가정 / 미결** — 착수 전 인지 필요.\u000a> - **1차 완료 전제**: 2차는 1차 MVP(로그인·온보딩·방·경주 실행)가 동작하는 상태 위에 얹는다.\u000a> - **도메인 변경(가정)**: 멀티기기·푸시를 위해 **Device(또는 PushToken) 도메인 신규**, 지도 표시를 위해 **TrackPoint 도메인 재도입**이 필요. 도메인 확정은 `/ib-domain`에서.\u000a> - **판정 모델 전환(미결)**: 1차의 "서버 릴레이(클라 판정)"에서 2차의 "서버 재검증"으로 이동. 재검증 강도(정합성 체크 수준 vs 완전 재계산)와 클라-서버 판정 충돌 시 우선순위 규칙 미정.\u000a> - **부정행위 정책(미결)**: 탐지 후 처리(경고/무효/제재) 수위와 오탐 대응 기준 미정.\u000a> - **푸시 인프라(미결)**: FCM/APNs 프로젝트·인증서 셋업, 백엔드 발송 파이프라인 스택 미정.\u000a> - **복귀 범위(미결)**: 얼마나 오래 끊겨도 복귀 허용할지(종료 시각 경과·이탈 판정과의 관계) 미정.\u000a> - **개인정보 관리 범위(미결)**: 열람/삭제/철회 중 2차 포함 범위와 법무 검토 필요.\u000a'),'draft',1,1783558735661,1783558735661);
CREATE TABLE IF NOT EXISTS "Domain" (
    "id" TEXT NOT NULL PRIMARY KEY,
    "projectId" TEXT NOT NULL,
    "name" TEXT NOT NULL,
    "description" TEXT,
    "columns" TEXT NOT NULL DEFAULT '[]',
    "status" TEXT NOT NULL DEFAULT 'draft',
    "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updatedAt" DATETIME NOT NULL, "lifecycle" TEXT,
    CONSTRAINT "Domain_projectId_fkey" FOREIGN KEY ("projectId") REFERENCES "Project" ("id") ON DELETE CASCADE ON UPDATE CASCADE
);
INSERT INTO Domain VALUES('cmrbzjtmr00011z1ivhzc2lbk','cmrby3y0000001znnofoo0a53','User','소셜 로그인(카카오/구글/애플)으로 가입한 앱 사용자','[{"name":"id","type":"int","constraints":"PK","description":"사용자 고유 ID"},{"name":"provider","type":"enum(kakao,google,apple)","constraints":"NN","description":"소셜 로그인 제공자"},{"name":"providerUserId","type":"string","constraints":"NN","description":"제공자가 부여한 사용자 식별자"},{"name":"nickname","type":"string","constraints":"NN","description":"표시 이름"},{"name":"profileImageUrl","type":"string","description":"프로필 이미지 URL"},{"name":"createdOn","type":"string","constraints":"NN, default: now()","description":"가입 시각 (YYYY-MM-DD HH:mm:ss)"},{"name":"providerKey","type":"-","constraints":"UQ(provider,providerUserId)","description":"제공자+제공자ID 조합은 유일"}]','approved',1783509572547,1783519750419,NULL);
INSERT INTO Domain VALUES('cmrbzjy7400031z1i4kv14kgo','cmrby3y0000001znnofoo0a53','Room','하나의 경주 세션. 방장이 목표 거리·제한 시간·시작 시각·정원을 설정해 개설하며 상태에 따라 생명주기를 갖는다.','[{"name":"id","type":"int","constraints":"PK","description":"방 고유 ID"},{"name":"hostUserId","type":"int","constraints":"FK→User, NN","description":"방장(생성자)"},{"name":"title","type":"string","description":"방 제목"},{"name":"goalDistanceMeter","type":"int","constraints":"NN","description":"목표 거리 (m)"},{"name":"goalLimitMinutes","type":"int","constraints":"NN","description":"제한 시간 (분)"},{"name":"startOn","type":"string","constraints":"NN","description":"예정 시작 시각 (YYYY-MM-DD HH:mm:ss)"},{"name":"capacity","type":"int","constraints":"NN","description":"최대 수용 인원"},{"name":"status","type":"enum(recruiting,ready,live,finished,canceled)","constraints":"NN, default: recruiting","description":"방 상태 (모집 중·모집 마감·경기 중·종료·취소)"},{"name":"finishedOn","type":"string","description":"경기 종료 시각 (YYYY-MM-DD HH:mm:ss)"},{"name":"createdOn","type":"string","constraints":"NN, default: now()","description":"방 생성 시각 (YYYY-MM-DD HH:mm:ss)"}]','approved',1783509578464,1783519765730,'{"states":[{"name":"recruiting","description":"모집 중 — 입장·방장 수정·강퇴 가능"},{"name":"ready","description":"모집 마감 — 시작 10분 전, 입장 불가"},{"name":"live","description":"경기 중"},{"name":"finished","description":"종료"},{"name":"canceled","description":"취소 — 모집 마감 시점 2명 미만"}],"transitions":[{"from":"[*]","to":"recruiting"},{"from":"recruiting","to":"ready","on":"시작 10분 전 모집 마감"},{"from":"ready","to":"canceled","on":"참가자 2명 미만"},{"from":"ready","to":"live","on":"시작 시간 도달"},{"from":"live","to":"finished","on":"전원 완주·제한시간 만료"},{"from":"finished","to":"[*]"},{"from":"canceled","to":"[*]"}]}');
INSERT INTO Domain VALUES('cmrbzmtbf00051z1i7c5sjkag','cmrby3y0000001znnofoo0a53','Participant','방(경주 세션)에 참가한 사용자. 참가 상태·현재 진행 거리·최종 등수를 관리한다. 실시간 리더보드와 결과·이력의 소스.','[{"name":"id","type":"int","constraints":"PK"},{"name":"roomId","type":"int","constraints":"FK→Room, NN"},{"name":"userId","type":"int","constraints":"FK→User, NN"},{"name":"status","type":"enum(joined,running,finished,dnf,kicked)","constraints":"NN, default: joined","description":"참가 상태"},{"name":"currentDistance","type":"int","constraints":"NN, default: 0","description":"현재까지 달린 누적 거리(m)"},{"name":"finishedOn","type":"string","description":"목표 도달/종료 시각"},{"name":"finalRank","type":"int","description":"최종 등수"},{"name":"joinedOn","type":"string","constraints":"NN, default: now()","description":"방 참가 시각"},{"name":"membership","type":"-","constraints":"UQ(roomId,userId)","description":"방·사용자 조합 유일성(중복 참가 방지)"}]','approved',1783509712107,1783560109265,'{"states":[{"name":"joined","description":"입장(대기)"},{"name":"running","description":"경주 중"},{"name":"finished","description":"완주 — 목표 거리 도달"},{"name":"dnf","description":"중도 이탈 / 제한시간 내 미완주"},{"name":"kicked","description":"방장에 의해 강퇴"}],"transitions":[{"from":"[*]","to":"joined","on":"입장"},{"from":"joined","to":"kicked","on":"방장 강퇴"},{"from":"joined","to":"running","on":"경기 시작"},{"from":"running","to":"finished","on":"목표 거리 도달"},{"from":"running","to":"dnf","on":"중도 이탈·제한시간 만료"},{"from":"finished","to":"[*]"},{"from":"dnf","to":"[*]"},{"from":"kicked","to":"[*]"}]}');
INSERT INTO Domain VALUES('cmrc4i1j8000v1z185z3b2pdk','cmrby3y0000001znnofoo0a53','Agreement','약관 마스터. 서비스 이용약관·개인정보 수집·이용·위치기반서비스(필수)와 마케팅 수신(선택) 약관을 버전 단위로 관리한다. 타입당 active 버전은 항상 1개만 존재한다.','[{"name":"id","type":"int","constraints":"PK","description":"약관 고유 ID"},{"name":"type","type":"enum(service,privacy,location,marketing)","constraints":"NN","description":"약관 유형 (서비스 이용·개인정보 수집·위치기반·마케팅)"},{"name":"version","type":"string","constraints":"NN","description":"약관 버전 (예: 1.0)"},{"name":"required","type":"boolean","constraints":"NN","description":"필수 동의 여부 (marketing만 false)"},{"name":"status","type":"enum(pending,active,archived)","constraints":"NN, default: pending","description":"약관 상태 (시행일 전 대기·시행 중·개정으로 보관)"},{"name":"title","type":"string","constraints":"NN","description":"약관 제목"},{"name":"content","type":"text","description":"약관 본문 (장문)"},{"name":"expectedActivatedOn","type":"string","constraints":"NN","description":"시행 예정일 (YYYY-MM-DD HH:mm:ss)"},{"name":"typeVersion","type":"-","constraints":"UQ(type,version)","description":"유형+버전 조합은 유일"},{"name":"oneActivePerType","type":"-","constraints":"UQ(type) WHERE status=active","description":"불변식 — 타입당 active 버전은 최대 1개 (부분 유니크 인덱스)"}]','approved',1783517887556,'2026-07-08 14:15:17','{"states":[{"name":"pending","description":"시행일 전 대기 — 아직 효력 없음"},{"name":"active","description":"시행 중 — 타입당 1개만 존재"},{"name":"archived","description":"개정으로 보관 — 신규 버전 active 시 이전 버전이 전이"}],"transitions":[{"from":"[*]","to":"pending","on":"약관 등록"},{"from":"pending","to":"active","on":"시행일 도래·활성화"},{"from":"active","to":"archived","on":"신규 버전 활성화"},{"from":"archived","to":"[*]"}]}');
INSERT INTO Domain VALUES('cmrc4i7x7000x1z18dy48lysi','cmrby3y0000001znnofoo0a53','UserConsent','사용자별 약관 동의 이력. 어떤 약관(버전)에 언제 동의/미동의했는지를 감사·분쟁 대비로 보존한다.','[{"name":"id","type":"int","constraints":"PK","description":"동의 기록 고유 ID"},{"name":"userId","type":"int","constraints":"FK→User, NN","description":"동의한 사용자"},{"name":"agreementId","type":"int","constraints":"FK→Agreement, NN","description":"대상 약관(버전)"},{"name":"isAgreed","type":"boolean","constraints":"NN","description":"동의 여부 (선택 약관은 false로 남길 수 있음)"},{"name":"consentedOn","type":"string","constraints":"NN","description":"동의/처리 시각 (YYYY-MM-DD HH:mm:ss)"},{"name":"userAgreement","type":"-","constraints":"UQ(userId,agreementId)","description":"한 사용자는 동일 약관(버전)에 한 번만 기록"}]','approved',1783517895835,1783519775169,NULL);
CREATE TABLE IF NOT EXISTS "Issue" (
    "id" TEXT NOT NULL PRIMARY KEY,
    "projectId" TEXT NOT NULL,
    "title" TEXT NOT NULL,
    "body" TEXT NOT NULL,
    "status" TEXT NOT NULL DEFAULT 'todo',
    "priority" TEXT NOT NULL DEFAULT 'medium',
    "labels" TEXT NOT NULL DEFAULT '[]',
    "parentId" TEXT,
    "planId" TEXT,
    "screenId" TEXT,
    "domainId" TEXT,
    "version" INTEGER NOT NULL DEFAULT 1,
    "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updatedAt" DATETIME NOT NULL,
    CONSTRAINT "Issue_projectId_fkey" FOREIGN KEY ("projectId") REFERENCES "Project" ("id") ON DELETE CASCADE ON UPDATE CASCADE,
    CONSTRAINT "Issue_parentId_fkey" FOREIGN KEY ("parentId") REFERENCES "Issue" ("id") ON DELETE SET NULL ON UPDATE CASCADE,
    CONSTRAINT "Issue_planId_fkey" FOREIGN KEY ("planId") REFERENCES "Plan" ("id") ON DELETE SET NULL ON UPDATE CASCADE,
    CONSTRAINT "Issue_domainId_fkey" FOREIGN KEY ("domainId") REFERENCES "Domain" ("id") ON DELETE SET NULL ON UPDATE CASCADE
);
INSERT INTO Issue VALUES('cmrc5xz6b000b1zkpqyae6533','cmrby3y0000001znnofoo0a53','[Auth] 소셜 로그인',unistr('카카오/구글/애플 소셜 로그인으로 가입·로그인한다. (자체 이메일 가입 없음)\u000a\u000a## 범위\u000a- 카카오 / 구글 / 애플 OAuth 연동\u000a- 신규/기존 사용자 판별 (User.provider + providerUserId)\u000a- 로그인 세션/토큰 관리, 자동 로그인\u000a\u000a## 완료 조건\u000a- 세 제공자로 각각 로그인 성공 → 인증 완료\u000a- 최초 사용자는 온보딩으로, 기존 사용자는 홈으로 분기\u000a- iOS에서 Sign in with Apple 병행 제공(심사 요건)\u000a\u000a관련 화면: login / 관련 도메인: User'),'todo','high','["auth"]',NULL,'cmrby4wah00021znnga9fbhfq','login','cmrbzjtmr00011z1ivhzc2lbk',14,1783520310612,1783522941642);
INSERT INTO Issue VALUES('cmrc5y54o000d1zkp8hyykjkb','cmrby3y0000001znnofoo0a53','[Onboarding] 최초 온보딩 · 약관 동의',unistr('최초 로그인(회원가입) 시 약관 동의와 프로필(닉네임) 설정을 마쳐야 서비스에 진입한다.\u000a\u000a## 범위\u000a- 필수 약관(서비스 이용약관·개인정보 수집·이용·위치기반서비스) + 선택 약관(마케팅) 동의\u000a- 닉네임 설정\u000a- 동의 이력 저장, 약관 버전 관리·개정 재동의\u000a\u000a## 완료 조건\u000a- 필수 약관 미동의 또는 닉네임 미입력 시 진입 차단\u000a- 온보딩 완료 시 동의 이력(UserConsent) 저장 후 홈 진입\u000a- 재로그인 시 온보딩 스킵, 필수 약관 개정 시 변경분 재동의\u000a\u000a관련 화면: onboarding / 관련 도메인: Agreement, UserConsent, User'),'todo','high','["onboarding","auth"]',NULL,'cmrby4wah00021znnga9fbhfq','onboarding','cmrc4i1j8000v1z185z3b2pdk',1,1783520318328,1783520318328);
INSERT INTO Issue VALUES('cmrc5y7mw000f1zkpe26zkowk','cmrby3y0000001znnofoo0a53','[Room] 방(경주 세션) 관리',unistr('경주 세션인 방을 생성·조회·입장하고, 대기실에서 방장 관리와 자동 모집 마감/취소를 처리한다.\u000a\u000a## 범위\u000a- 방 생성 (목표 거리·제한 시간·시작 시간·최대 인원)\u000a- 방 목록/입장 (모집 중만 입장, 지각 입장 없음)\u000a- 대기실: 참가자 목록·카운트다운·완주 기준 페이스, 방장 조건 수정·강퇴\u000a- 자동 모집 마감(시작 10분 전)·2명 미만 시 자동 취소\u000a\u000a## 완료 조건\u000a- Room 상태 흐름(recruiting→ready→live→finished, ready→canceled) 준수\u000a- 각 세부 기능은 하위 이슈 참조\u000a\u000a관련 도메인: Room'),'todo','high','["room"]',NULL,'cmrby4wah00021znnga9fbhfq',NULL,'cmrbzjy7400031z1i4kv14kgo',1,1783520321576,1783520321576);
INSERT INTO Issue VALUES('cmrc5ys21000h1zkpe8natml1','cmrby3y0000001znnofoo0a53','[Auth] OAuth 제공자 연동 (카카오·구글·애플)',unistr('각 소셜 제공자 OAuth 플로우를 연동하고 콜백에서 User를 조회/생성한다.\u000a\u000a## 완료 조건\u000a- 카카오·구글·애플 각각 인증 성공 후 provider·providerUserId로 User upsert\u000a- UQ(provider, providerUserId) 위반 없이 기존 계정 재사용\u000a- 애플: Sign in with Apple(iOS 필수)'),'todo','high','["auth"]','cmrc5xz6b000b1zkpqyae6533','cmrby4wah00021znnga9fbhfq','login','cmrbzjtmr00011z1ivhzc2lbk',1,1783520348041,1783520348041);
INSERT INTO Issue VALUES('cmrc5ytlo000j1zkpjku9hvg9','cmrby3y0000001znnofoo0a53','[Auth] 로그인 세션·토큰 관리 및 신규/기존 분기',unistr('로그인 성공 후 세션/토큰을 발급·유지하고 자동 로그인을 지원한다. 온보딩 완료 여부로 진입 화면을 분기한다.\u000a\u000a## 완료 조건\u000a- 토큰 발급·갱신·만료 처리, 앱 재실행 시 자동 로그인\u000a- 최초 사용자(온보딩 미완료)는 온보딩, 기존 사용자는 홈으로 분기'),'todo','high','["auth"]','cmrc5xz6b000b1zkpqyae6533','cmrby4wah00021znnga9fbhfq',NULL,'cmrbzjtmr00011z1ivhzc2lbk',1,1783520350044,1783520350044);
INSERT INTO Issue VALUES('cmrc5yx9u000l1zkpsxusze3a','cmrby3y0000001znnofoo0a53','[Onboarding] 약관 동의 화면 및 필수 검증',unistr('필수/선택 약관 동의 UI와 진입 차단 검증을 구현한다.\u000a\u000a## 완료 조건\u000a- 전체 동의 토글, 개별 약관 보기(본문)\u000a- 필수 약관(서비스·개인정보·위치기반) 미동의 시 진행 차단\u000a- 선택 약관(마케팅)은 미동의로 진행 가능'),'todo','high','["onboarding"]','cmrc5y54o000d1zkp8hyykjkb','cmrby4wah00021znnga9fbhfq','onboarding','cmrc4i1j8000v1z185z3b2pdk',1,1783520354803,1783520354803);
INSERT INTO Issue VALUES('cmrc5z095000n1zkp5l0q57qr','cmrby3y0000001znnofoo0a53','[Onboarding] 닉네임·프로필 설정',unistr('온보딩에서 닉네임을 설정해 User 프로필을 완성한다.\u000a\u000a## 완료 조건\u000a- 닉네임 입력 필수, 미입력 시 진행 차단\u000a- 저장 시 User.nickname 반영'),'todo','high','["onboarding"]','cmrc5y54o000d1zkp8hyykjkb','cmrby4wah00021znnga9fbhfq','onboarding','cmrbzjtmr00011z1ivhzc2lbk',1,1783520358666,1783520358666);
INSERT INTO Issue VALUES('cmrc5z30s000p1zkpaopnjrn4','cmrby3y0000001znnofoo0a53','[Onboarding] 동의 이력 저장 (UserConsent)',unistr('사용자가 동의/미동의한 약관(버전)을 UserConsent로 기록한다.\u000a\u000a## 완료 조건\u000a- 약관별 isAgreed·consentedOn 저장, UQ(userId, agreementId) 준수\u000a- 감사·분쟁 대비로 이력 보존'),'todo','high','["onboarding"]','cmrc5y54o000d1zkp8hyykjkb','cmrby4wah00021znnga9fbhfq',NULL,'cmrc4i7x7000x1z18dy48lysi',1,1783520362252,1783520362252);
INSERT INTO Issue VALUES('cmrc5z60n000r1zkp8qtb397i','cmrby3y0000001znnofoo0a53','[Onboarding] 약관 버전 관리 및 개정 재동의',unistr('약관을 버전 단위로 관리하고, 필수 약관 개정 시 기존 사용자에게 변경분 재동의를 요구한다.\u000a\u000a## 완료 조건\u000a- Agreement 상태 흐름(pending→active→archived) 및 타입당 active 1개 불변식 준수\u000a- 재로그인 시 미동의 상태인 최신 필수 약관이 있으면 재동의 화면 노출'),'todo','high','["onboarding"]','cmrc5y54o000d1zkp8hyykjkb','cmrby4wah00021znnga9fbhfq','profile','cmrc4i1j8000v1z185z3b2pdk',2,1783520366136,1783557798218);
INSERT INTO Issue VALUES('cmrc5zc6b000t1zkpvlwyvx9w','cmrby3y0000001znnofoo0a53','[Room] 방 생성',unistr('목표 거리·제한 시간·시작 시간·최대 인원을 설정해 방을 개설한다.\u000a\u000a## 완료 조건\u000a- 방 생성 시 status=recruiting, hostUserId=생성자\u000a- 입력값 검증(거리>0, 시간>0, 정원>=2)'),'todo','high','["room"]','cmrc5y7mw000f1zkpe26zkowk','cmrby4wah00021znnga9fbhfq','room-create','cmrbzjy7400031z1i4kv14kgo',1,1783520374116,1783520374116);
INSERT INTO Issue VALUES('cmrc5zeav000v1zkpaxqklbxf','cmrby3y0000001znnofoo0a53','[Room] 방 목록 · 입장',unistr('참여 가능한 방을 목록으로 보여주고 입장을 처리한다.\u000a\u000a## 완료 조건\u000a- 모집 중(recruiting) 방에만 입장 가능, 지각 입장 없음\u000a- 정원 초과 입장 차단, 모집 중 방에 시작까지 남은 시간 표시(1시간 초과=시간, 이내=분)\u000a- 입장 시 Participant 생성(status=joined)'),'todo','high','["room"]','cmrc5y7mw000f1zkpe26zkowk','cmrby4wah00021znnga9fbhfq','home','cmrbzjy7400031z1i4kv14kgo',1,1783520376871,1783520376871);
INSERT INTO Issue VALUES('cmrc5zgsk000x1zkpv5st1x6l','cmrby3y0000001znnofoo0a53','[Room] 대기실 · 방장 관리',unistr('대기실에서 참가자 목록·카운트다운·완주 기준 페이스를 보여주고, 방장이 조건 수정·강퇴를 수행한다.\u000a\u000a## 완료 조건\u000a- 완주 기준 페이스 = 제한시간 ÷ 목표거리 표시\u000a- 모집 중에만 방장이 목표 거리·제한 시간·최대 인원 수정 및 참가자 강퇴 가능\u000a- 강퇴 시 해당 Participant 제거(status=kicked)'),'todo','high','["room"]','cmrc5y7mw000f1zkpe26zkowk','cmrby4wah00021znnga9fbhfq','waiting-room','cmrbzjy7400031z1i4kv14kgo',1,1783520380100,1783520380100);
INSERT INTO Issue VALUES('cmrc5zii9000z1zkpsve8xueh','cmrby3y0000001znnofoo0a53','[Room] 자동 모집 마감 · 취소',unistr('시작 시간 기준으로 방 상태를 자동 전이한다.\u000a\u000a## 완료 조건\u000a- 시작 10분 전 recruiting→ready(입장 차단)\u000a- ready 진입 시 참가자 2명 미만이면 canceled로 전이 + 참가자 취소 안내\u000a- 시작 시간 도달 시 ready→live'),'todo','high','["room"]','cmrc5y7mw000f1zkpe26zkowk','cmrby4wah00021znnga9fbhfq','race-cancelled','cmrbzjy7400031z1i4kv14kgo',2,1783520382321,1783558630683);
INSERT INTO Issue VALUES('cmrcsoze60007rwt4brdpphoa','cmrby3y0000001znnofoo0a53','[Race] 실시간 GPS 러닝',unistr('경주 중 기기 GPS로 이동 거리를 계산하고 WebSocket으로 실시간 공유한다. 서버 시각 기준으로 동시에 출발/종료하며, 판정은 서버 릴레이(클라이언트 계산값 신뢰) 모델을 따른다.\u000a\u000a## 범위\u000a- 위치 권한 확보(백그라운드 포함), 거부 시 앱 사용 불가 처리\u000a- GPS 이동 거리 누적 계산(클라이언트) 및 진행 상태 산출\u000a- WebSocket 진행(거리/페이스) 송수신\u000a- 백그라운드 위치 추적 유지\u000a- 네트워크 단절 시 재연결·거리 재동기화\u000a- 서버 시각 기준 start/ends 신호 수신·카운트다운\u000a\u000a## 완료 조건\u000a- 각 세부 기능은 하위 이슈 참조\u000a- 원시 GPS 좌표는 보존하지 않음(TrackPoint 미도입), 진행값은 Participant.currentDistance로만 전송\u000a\u000a관련 도메인: Participant / 관련 화면: race'),'todo','high','["race","gps"]',NULL,'cmrby4wah00021znnga9fbhfq','race','cmrbzmtbf00051z1i7c5sjkag',1,1783558522159,1783558522159);
INSERT INTO Issue VALUES('cmrcsp3f60009rwt4t8f82mgv','cmrby3y0000001znnofoo0a53','[Race] 실시간 리더보드',unistr('경주 중 참가자들의 거리 기준 순위·페이스를 실시간으로 계산해 리더보드로 표시한다. 동기화 지연 목표 3초 이내.\u000a\u000a## 범위\u000a- 참가자 진행값(Participant.currentDistance) 기준 실시간 순위 계산 — 순위는 휘발성이라 별도 컬럼에 저장하지 않고 브로드캐스트로만 전달\u000a- 리더보드 UI(선두·본인 강조)와 내 진행 패널(거리/목표 대비 진행률/페이스/현재 순위)\u000a- 재접속 시 최신 리더보드 스냅샷 재수신\u000a\u000a## 완료 조건\u000a- 타 참가자 진행이 3초 이내로 리더보드에 반영\u000a- 순위가 거리 기준으로 정확히 정렬\u000a\u000a관련 도메인: Participant / 관련 화면: race'),'todo','high','["race","realtime"]',NULL,'cmrby4wah00021znnga9fbhfq','race','cmrbzmtbf00051z1i7c5sjkag',2,1783558527378,1783560974739);
INSERT INTO Issue VALUES('cmrcsp8yz000brwt4qo6q9f0d','cmrby3y0000001znnofoo0a53','[Race] 등수 판정',unistr('목표 도달 순서로 등수를 확정하고, 제한 시간 만료·이탈을 처리해 최종 순위를 낸다. 판정은 클라이언트가 보낸 도달 이벤트의 서버 도착 순서로 확정한다(재계산 없음).\u000a\u000a## 범위\u000a- 목표 거리 도달 순서로 등수 확정, 동시 도달 시 공동 순위\u000a- 제한 시간 만료 종료 처리\u000a- 미완주·중도 이탈·앱 강제 종료 = dnf → 완주자 뒤 누적 거리순 정렬\u000a- Participant.finalRank·status 확정, Room→finished 전이\u000a\u000a## 완료 조건\u000a- 도달 순 등수·공동 순위 정확\u000a- 완주자 뒤 미완주자 누적 거리순 정렬\u000a- 종료 시 Room 상태 finished로 전이\u000a\u000a관련 도메인: Participant·Room / 관련 화면: result'),'todo','high','["race","ranking"]',NULL,'cmrby4wah00021znnga9fbhfq','result','cmrbzmtbf00051z1i7c5sjkag',1,1783558534571,1783558534571);
INSERT INTO Issue VALUES('cmrcspa1u000drwt4wyxzkl2g','cmrby3y0000001znnofoo0a53','[Race] 결과 & 경주 이력',unistr('경주 종료 후 결과를 집계해 결과 화면으로 보여주고, 사용자별 경주 이력에서 지난 결과를 조회한다.\u000a\u000a## 범위\u000a- 경주 결과 집계(최종 순위·개인 기록: 거리/시간/페이스) 및 결과 화면\u000a- 사용자별 경주 이력 목록·상세 조회\u000a- 시간·페이스는 Room.startOn/finishedOn·Participant 값에서 파생\u000a\u000a## 완료 조건\u000a- 결과 화면에 최종 순위·내 기록 표시\u000a- 경주 이력에서 지난 경주의 등수·거리·시간·페이스 확인\u000a\u000a관련 도메인: Participant·Room / 관련 화면: result·history'),'todo','medium','["race","history"]',NULL,'cmrby4wah00021znnga9fbhfq','result','cmrbzmtbf00051z1i7c5sjkag',1,1783558535971,1783558535971);
INSERT INTO Issue VALUES('cmrcspsq9000frwt4k47e97a8','cmrby3y0000001znnofoo0a53','[Race] 위치 권한 확보 · 거부 시 앱 사용 불가',unistr('위치 권한(백그라운드 포함)을 요청하고, 거부 시 앱 사용 불가 안내 화면으로 차단한다.\u000a\u000a## 완료 조건\u000a- 권한 허용 시 정상 진입, 거부/미허용 시 안내 화면 노출\u000a- 설정 이동·재확인 흐름 제공 (시나리오 #15)'),'todo','high','["race","gps"]','cmrcsoze60007rwt4brdpphoa','cmrby4wah00021znnga9fbhfq','location-denied',NULL,1,1783558560177,1783558560177);
INSERT INTO Issue VALUES('cmrcspwqn000hrwt45qgzhpy0','cmrby3y0000001znnofoo0a53','[Race] GPS 이동 거리 계산 · 진행 상태 산출',unistr('기기 GPS 스트림으로 이동 거리를 누적 계산하고 페이스·목표 대비 진행률을 산출한다.\u000a\u000a## 완료 조건\u000a- 실사용 러닝에서 신뢰 가능한 누적 거리·페이스 산출 (오차 ±5% 목표)\u000a- 목표 도달 판정(클라이언트) 및 도달 이벤트 생성'),'todo','high','["race","gps"]','cmrcsoze60007rwt4brdpphoa','cmrby4wah00021znnga9fbhfq','race','cmrbzmtbf00051z1i7c5sjkag',1,1783558565375,1783558565375);
INSERT INTO Issue VALUES('cmrcsq3eq000jrwt4006g31zw','cmrby3y0000001znnofoo0a53','[Race] WebSocket 진행 송수신 채널',unistr('경주 세션 WebSocket 채널로 내 진행값(거리/페이스)을 주기 송신하고, 타 참가자 진행을 수신한다. 서버는 재계산 없이 릴레이·순서 확정.\u000a\u000a## 완료 조건\u000a- 진행 송신 및 브로드캐스트 수신 동작, 지연 3초 이내\u000a- Participant.currentDistance 갱신 반영'),'todo','high','["race","realtime"]','cmrcsoze60007rwt4brdpphoa','cmrby4wah00021znnga9fbhfq','race','cmrbzmtbf00051z1i7c5sjkag',1,1783558574018,1783558574018);
INSERT INTO Issue VALUES('cmrcsq5wh000lrwt41asy9c67','cmrby3y0000001znnofoo0a53','[Race] 백그라운드 위치 추적 유지',unistr('화면이 꺼지거나 앱이 백그라운드여도 GPS 추적과 진행 송신이 끊기지 않게 한다. (앱 강제 종료 후 복귀는 MVP 범위 밖)\u000a\u000a## 완료 조건\u000a- 백그라운드/화면 꺼짐 상태에서 추적·송신 지속 (iOS/Android)\u000a- 배터리 소모 실사용 가능 수준'),'todo','high','["race","mobile"]','cmrcsoze60007rwt4brdpphoa','cmrby4wah00021znnga9fbhfq','race',NULL,1,1783558577249,1783558577249);
INSERT INTO Issue VALUES('cmrcsq7j0000nrwt4kj5ufzmj','cmrby3y0000001znnofoo0a53','[Race] 네트워크 단절 재연결 · 거리 재동기화',unistr('러닝 중 네트워크 단절 시 WebSocket 재연결하고, 클라이언트가 보유한 현재 누적 거리를 재전송해 서버 상태를 복구한다.\u000a\u000a## 완료 조건\u000a- 단절 후 재연결 시 진행 유실 없이 서버 반영\u000a- 재연결 시 최신 리더보드 스냅샷 재수신'),'todo','high','["race","reliability"]','cmrcsoze60007rwt4brdpphoa','cmrby4wah00021znnga9fbhfq','race','cmrbzmtbf00051z1i7c5sjkag',1,1783558579356,1783558579356);
INSERT INTO Issue VALUES('cmrcsqdt8000prwt422byd542','cmrby3y0000001znnofoo0a53','[Race] 서버 시각 기준 start/ends 신호 · 카운트다운',unistr('예약 startOn 기준으로 서버가 "start at T / ends at T+limit" 신호를 브로드캐스트하고, 클라이언트는 서버 시각 오프셋으로 카운트다운·동시 출발/종료한다.\u000a\u000a## 완료 조건\u000a- 참가자 전원 동시 출발(시계 오차 보정)\u000a- ends 도달 시 클라이언트 종료 처리 (시나리오 #10)'),'todo','high','["race","realtime"]','cmrcsoze60007rwt4brdpphoa','cmrby4wah00021znnga9fbhfq','race','cmrbzjy7400031z1i4kv14kgo',1,1783558587500,1783558587500);
INSERT INTO Issue VALUES('cmrcsqhcg000rrwt4y4ee9zn9','cmrby3y0000001znnofoo0a53','[Race] 거리 기준 실시간 순위 계산',unistr('수신한 참가자 진행값(Participant.currentDistance)을 기준으로 실시간 순위를 계산해 리더보드로 브로드캐스트한다. 순위는 휘발성 값이라 별도 컬럼(currentRank 등)에 저장하지 않는다.\u000a\u000a## 완료 조건\u000a- 거리 내림차순 순위 정확, 동률 처리\u000a- 진행 갱신마다 순위 재계산'),'todo','high','["race","realtime"]','cmrcsp3f60009rwt4t8f82mgv','cmrby4wah00021znnga9fbhfq','race','cmrbzmtbf00051z1i7c5sjkag',2,1783558592081,1783560981037);
INSERT INTO Issue VALUES('cmrcsqihx000trwt4234ydxgm','cmrby3y0000001znnofoo0a53','[Race] 리더보드 · 내 진행 UI',unistr('리더보드(선두·본인 강조)와 내 진행 패널(거리/목표 대비 진행률/페이스/현재 순위)을 실시간 렌더한다.\u000a\u000a## 완료 조건\u000a- 내 진행/리더보드가 실시간 갱신 (시나리오 #11)\u000a- 재접속 시 즉시 복구'),'todo','high','["race","ui"]','cmrcsp3f60009rwt4t8f82mgv','cmrby4wah00021znnga9fbhfq','race','cmrbzmtbf00051z1i7c5sjkag',1,1783558593574,1783558593574);
INSERT INTO Issue VALUES('cmrcsqjsi000vrwt44gdi67jv','cmrby3y0000001znnofoo0a53','[Race] 목표 도달 순 확정 · 공동 순위',unistr('완주자의 목표 도달 이벤트를 서버 도착 순서로 등수 확정하고, 동시 도달은 공동 순위로 처리한다.\u000a\u000a## 완료 조건\u000a- 도달 순 등수 확정, 동시 도달 공동 순위 (시나리오 #12)\u000a- 완주자 finalRank·status(finished) 확정'),'todo','high','["race","ranking"]','cmrcsp8yz000brwt4qo6q9f0d','cmrby4wah00021znnga9fbhfq','result','cmrbzmtbf00051z1i7c5sjkag',1,1783558595250,1783558595250);
INSERT INTO Issue VALUES('cmrcsqph9000xrwt4dbnjlgw9','cmrby3y0000001znnofoo0a53','[Race] 제한 시간 만료 종료 · 이탈/강제종료 dnf 처리',unistr('제한 시간 만료 시 경주를 종료하고, 미완주·중도 이탈·앱 강제 종료 참가자는 dnf로 처리해 완주자 뒤 누적 거리순으로 정렬한다.\u000a\u000a## 완료 조건\u000a- 제한 시간 만료 종료 트리거\u000a- dnf 참가자 누적 거리순 정렬 (시나리오 #13)'),'todo','high','["race","ranking"]','cmrcsp8yz000brwt4qo6q9f0d','cmrby4wah00021znnga9fbhfq','result','cmrbzmtbf00051z1i7c5sjkag',1,1783558602621,1783558602621);
INSERT INTO Issue VALUES('cmrcsqxgk000zrwt4eif2nahz','cmrby3y0000001znnofoo0a53','[Race] 최종 순위 확정 · Room finished 전이',unistr('완주자·dnf를 합쳐 최종 순위를 확정하고 Room 상태를 finished로 전이하며 finishedOn을 기록한다.\u000a\u000a## 완료 조건\u000a- 전체 참가자 finalRank 확정\u000a- Room.status=finished, finishedOn 기록'),'todo','high','["race","ranking"]','cmrcsp8yz000brwt4qo6q9f0d','cmrby4wah00021znnga9fbhfq','result','cmrbzjy7400031z1i4kv14kgo',1,1783558612964,1783558612964);
INSERT INTO Issue VALUES('cmrcsr1c60011rwt4alblsjk4','cmrby3y0000001znnofoo0a53','[Race] 경주 결과 집계 · 결과 화면',unistr('종료된 경주의 최종 순위와 개인 기록(거리/시간/페이스)을 집계해 결과 화면으로 보여준다.\u000a\u000a## 완료 조건\u000a- 결과 화면에 최종 순위·내 기록 표시 (시나리오 #14)\u000a- 시간/페이스는 Room·Participant 값에서 파생'),'todo','medium','["race","result"]','cmrcspa1u000drwt4wyxzkl2g','cmrby4wah00021znnga9fbhfq','result','cmrbzmtbf00051z1i7c5sjkag',1,1783558617990,1783558617990);
INSERT INTO Issue VALUES('cmrcsr5a80013rwt43bsuy2ot','cmrby3y0000001znnofoo0a53','[Race] 사용자별 경주 이력 조회',unistr('사용자가 참여했던 지난 경주들을 이력 목록·상세로 조회한다.\u000a\u000a## 완료 조건\u000a- 이력 목록에서 지난 경주의 등수·거리·시간·페이스 확인\u000a- Participant·Room 조인으로 사용자별 조회'),'todo','medium','["race","history"]','cmrcspa1u000drwt4wyxzkl2g','cmrby4wah00021znnga9fbhfq','history','cmrbzmtbf00051z1i7c5sjkag',1,1783558623104,1783558623104);
CREATE TABLE IF NOT EXISTS "PlanVersion" (
    "id" TEXT NOT NULL PRIMARY KEY,
    "planId" TEXT NOT NULL,
    "version" INTEGER NOT NULL,
    "title" TEXT NOT NULL,
    "content" TEXT NOT NULL,
    "status" TEXT NOT NULL,
    "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, "label" TEXT,
    CONSTRAINT "PlanVersion_planId_fkey" FOREIGN KEY ("planId") REFERENCES "Plan" ("id") ON DELETE CASCADE ON UPDATE CASCADE
);
INSERT INTO PlanVersion VALUES('cmrbz4tv000041znn7ersip9m','cmrby4wah00021znnga9fbhfq',1,'1차 MVP 기획서',unistr('# 추노\u000a\u000a## 1. 개요 / 목적\u000a\u000a> 🎯 **목적** — 장소에 상관없이, 실시간 GPS로 각자 뛰면서 "누가 목표 거리에 먼저 도달하는가"를 겨루는 경쟁 러닝 앱.\u000a\u000a같은 트랙에 모이지 않아도 방 하나로 원격 러닝 대결이 성립한다. 러닝을 습관화하고 싶지만 동기부여가 부족한 사람에게 "혼자 뛰어도 함께 경쟁하는" 경험을 제공한다. 1차 MVP는 Android/iOS 두 플랫폼을 Flutter 단일 코드베이스로 동시 지원하며, 방 생성 → 대기 → 실시간 경주 → 등수 판정 → 결과의 한 사이클을 안정적으로 완주시키는 것을 목표로 한다.\u000a\u000a## 2. 타깃 사용자 & 유스케이스\u000a\u000a| 페르소나 | 니즈 | 핵심 유스케이스 |\u000a| --- | --- | --- |\u000a| 동기부여가 필요한 러너 | 혼자 뛰면 지루하고 꾸준하지 못함 | 친구와 방을 만들어 목표 거리 대결, 이겨서 성취감을 얻는다 |\u000a| 원격의 지인 그룹 | 서로 다른 지역에 살아 같이 못 뜀 | 각자 동네에서 같은 방에 입장해 동시에 스타트, 실시간 순위를 본다 |\u000a| 가벼운 경쟁을 즐기는 사람 | 기록 경쟁·게임성 | 짧은 거리(예: 3km) 방에 참여해 빠르게 승부를 낸다 |\u000a\u000a## 3. 핵심 기능 (MVP)\u000a\u000a| 우선순위 | 기능 | 설명 |\u000a| --- | --- | --- |\u000a| 높음 | 소셜 로그인 | 카카오 / 구글 / 애플 인증으로 가입·로그인 (자체 이메일 가입 없음) |\u000a| 높음 | 방 생성 | 목표 거리·제한 시간·시작 시간·최대 인원을 설정해 방 개설 |\u000a| 높음 | 방 목록 / 입장 | 모집 중 상태의 방에만 입장 가능. 지각 입장 없음 |\u000a| 높음 | 대기실 & 방장 관리 | 현 인원/정원·참가자 목록·시작 카운트다운 표시. 모집 중 방장이 목표 거리·제한 시간·최대 인원 수정 및 참가자 강퇴 가능 |\u000a| 높음 | 자동 모집 마감·취소 | 시작 10분 전 모집 마감. 이 시점에 참가자 2명 미만이면 경주 자동 취소 |\u000a| 높음 | 실시간 GPS 러닝 | 디바이스 GPS로 이동 거리 누적, WebSocket으로 참가자 위치/거리 실시간 동기화 |\u000a| 높음 | 실시간 리더보드 | 경주 중 참가자 순위·거리·페이스를 실시간 표시 |\u000a| 높음 | 등수 판정 | 클라이언트 GPS 기반으로 목표 도달 순서에 따라 등수 확정. 동시 도달 시 공동 순위. 미완주·중도 이탈자는 완주자 뒤 누적 거리순 |\u000a| 보통 | 결과 & 경주 이력 | 경주 종료 후 사용자별 경주 이력에서 결과(등수·거리·시간·페이스) 조회 |\u000a| 낮음 | 경주 중 지도 표시 | 러닝 화면에 본인 경로/지도 표시 (여력 시) |\u000a\u000a> 📌 **참고** — 방(Room)의 상태(모집 중·모집 마감·경기 중·종료·취소)와 전이 규칙은 도메인 문서(`/ib-domain`)에서 엔티티 속성으로 정의한다.\u000a\u000a## 4. 범위 밖 (Out of Scope)\u000a\u000a> ⚠️ **범위 밖** — 이번 1차 MVP에서 하지 않는다.\u000a> - 부정행위 방지 (GPS 스푸핑·차량 이동 탐지 등) — 차기 버전에서 검토\u000a> - GPS 튐(순간 거리 급증) 보정 — 이번 MVP에서는 무시\u000a> - 서버 측 목표 도달 재검증 (MVP는 클라이언트 판정)\u000a> - 소셜 기능 (친구, 팔로우, 채팅)\u000a> - 랭킹/리그/시즌, 리워드·포인트\u000a> - 코스 지정형(특정 경로 완주), 팀전\u000a> - 웨어러블(스마트워치) 연동\u000a> - 자체 이메일/비밀번호 회원가입\u000a\u000a## 5. 비기능 요구사항\u000a\u000a| 항목 | 요구사항/기준 |\u000a| --- | --- |\u000a| 플랫폼 | Flutter 단일 코드베이스로 Android / iOS 동시 지원 |\u000a| 실시간성 | 리더보드/위치 동기화 지연 수 초 이내 (WebSocket) |\u000a| 위치 권한 | 위치 권한(백그라운드 포함)은 필수. 거부 시 앱 사용 불가 처리 |\u000a| 위치 정확도 | GPS 이동 거리 오차 허용 범위 내, 백그라운드 위치 추적 지원 |\u000a| 안정성 | 방 생성 → 경주 완료까지 크래시 없이 완주 가능 |\u000a| 복원력 | 러닝 중 네트워크 단절 시 재연결·거리 재동기화 처리 |\u000a| 인증/보안 | OAuth 기반 소셜 로그인 (카카오/구글/애플) |\u000a| 배터리 | 지속 GPS 추적에도 실사용 가능한 배터리 소모 수준 |\u000a\u000a## 6. 성공 지표\u000a\u000a| 지표 | 목표값 | 측정 방법 |\u000a| --- | --- | --- |\u000a| 경주 완주율 | 시작한 경주의 95% 이상 크래시 없이 결과 도달 | 세션 로그/크래시 리포트 |\u000a| 리더보드 동기화 지연 | 평균 3초 이내 | 서버-클라이언트 타임스탬프 비교 |\u000a| 거리 측정 오차 | 실측 대비 ±5% 이내 | 기준 코스 실측 테스트 |\u000a| 리텐션(참고) | 첫 경주 후 재참여율 측정 | 사용자별 경주 참여 이벤트 |\u000a\u000a## 7. 테스트 시나리오\u000a\u000a| # | 시나리오 | 절차 (핵심 흐름) | 기대 결과 |\u000a| --- | --- | --- | --- |\u000a| 1 | 소셜 로그인 | 앱 실행 → 카카오/구글/애플 중 선택 → 인증 | 로그인 성공, 홈 진입 |\u000a| 2 | 방 생성·입장 | 홈 → 방 생성(거리·시간·정원 입력) → 다른 사용자 입장 | 대기실에 현 인원/정원·참가자 반영, 모집 중 상태 |\u000a| 3 | 방장 조건 수정·강퇴 | 모집 중 방장이 목표 거리 변경, 참가자 강퇴 | 변경 즉시 반영, 강퇴된 사용자 방에서 제거 |\u000a| 4 | 지각 입장 차단 | 모집 마감/경기 중 방에 입장 시도 | 입장 거부 |\u000a| 5 | 자동 취소 | 시작 10분 전(모집 마감) 참가자 1명 | 경주 취소, 참가자에 취소 안내 |\u000a| 6 | 동시 스타트 | 2명 이상 유지 → 시작 시간 도달 | 경기 시작, 참가자 전원 동시 스타트 |\u000a| 7 | 실시간 경주 | 각자 러닝 → 거리 누적 전송 | 리더보드에 실시간 순위·거리 갱신 |\u000a| 8 | 등수 판정 (공동 순위) | 참가자들이 목표 거리 도달, 일부 동시 도달 | 도달 순 등수 확정, 동시 도달자는 공동 순위 |\u000a| 9 | 제한 시간 만료·이탈 | 목표 미도달 또는 중도 이탈 상태로 종료 | 완주자 뒤로 누적 거리순 정렬, 경주 종료 |\u000a| 10 | 경주 이력 확인 | 종료 후 사용자 경주 이력 진입 | 최종 등수·개인 기록(거리/시간/페이스) 표시 |\u000a| 11 | 위치 권한 거부 | 위치 권한 거부/미허용 | 앱 사용 불가 안내 화면 |\u000a\u000a## 8. 핵심 가정 / 미결 질문\u000a\u000a> 📝 **가정 / 미결** — 확정 안 된 사항 및 의도적 단순화. 착수 전 인지 필요.\u000a> - **클라이언트 판정의 신뢰성(의도적 단순화)**: MVP는 목표 도달을 클라이언트 GPS 계산으로 판정하고 GPS 튐도 무시한다. 조작·오차에 취약하므로 차기 버전에서 서버 검증·부정행위 방지로 보완 전제.\u000a> - **백엔드 스택 미정**: 서버 언어/프레임워크, WebSocket 서버, DB 선정 필요.\u000a> - **거리 측정 방식**: 순수 GPS 누적 vs 스텝/센서 융합 — 정확도/배터리 트레이드오프.\u000a> - **동시 시작 정합성**: startTime 기준 클라이언트 시계 오차 보정 방식.\u000a> - **백그라운드 추적 정책**: iOS/Android 백그라운드 위치 권한·배터리 정책 대응.\u000a> - **알림 연동(미결)**: 시작 임박·경주 시작/종료 푸시 알림 범위 (저장소 내 알림 기능 문서와 연계 여부).\u000a> - **진행 중 경주 복귀(미결)**: 앱 강제 종료 후 재실행 시 진행 중 경주 자동 복귀 여부.\u000a> - **가정**: 애플 로그인 포함으로 iOS 소셜 로그인 심사 요건(Sign in with Apple 병행 제공) 충족.\u000a'),'draft',1783508873004,NULL);
INSERT INTO PlanVersion VALUES('cmrbz4v3d00061znnengk3h3z','cmrby4wah00021znnga9fbhfq',2,'1차 MVP 기획서',unistr('# 추노\u000a\u000a## 1. 개요 / 목적\u000a\u000a> 🎯 **목적** — 장소에 상관없이, 실시간 GPS로 각자 뛰면서 "누가 목표 거리에 먼저 도달하는가"를 겨루는 경쟁 러닝 앱.\u000a\u000a같은 트랙에 모이지 않아도 방 하나로 원격 러닝 대결이 성립한다. 러닝을 습관화하고 싶지만 동기부여가 부족한 사람에게 "혼자 뛰어도 함께 경쟁하는" 경험을 제공한다. 1차 MVP는 Android/iOS 두 플랫폼을 Flutter 단일 코드베이스로 동시 지원하며, 방 생성 → 대기 → 실시간 경주 → 등수 판정 → 결과의 한 사이클을 안정적으로 완주시키는 것을 목표로 한다.\u000a\u000a## 2. 타깃 사용자 & 유스케이스\u000a\u000a| 페르소나 | 니즈 | 핵심 유스케이스 |\u000a| --- | --- | --- |\u000a| 동기부여가 필요한 러너 | 혼자 뛰면 지루하고 꾸준하지 못함 | 친구와 방을 만들어 목표 거리 대결, 이겨서 성취감을 얻는다 |\u000a| 원격의 지인 그룹 | 서로 다른 지역에 살아 같이 못 뜀 | 각자 동네에서 같은 방에 입장해 동시에 스타트, 실시간 순위를 본다 |\u000a| 가벼운 경쟁을 즐기는 사람 | 기록 경쟁·게임성 | 짧은 거리(예: 3km) 방에 참여해 빠르게 승부를 낸다 |\u000a\u000a## 3. 핵심 기능 (MVP)\u000a\u000a| 우선순위 | 기능 | 설명 |\u000a| --- | --- | --- |\u000a| 높음 | 소셜 로그인 | 카카오 / 구글 / 애플 인증으로 가입·로그인 (자체 이메일 가입 없음) |\u000a| 높음 | 방 생성 | 목표 거리·제한 시간·시작 시간·최대 인원을 설정해 방 개설 |\u000a| 높음 | 방 목록 / 입장 | 모집 중 상태의 방에만 입장 가능. 지각 입장 없음 |\u000a| 높음 | 대기실 & 방장 관리 | 현 인원/정원·참가자 목록·시작 카운트다운 표시. 모집 중 방장이 목표 거리·제한 시간·최대 인원 수정 및 참가자 강퇴 가능 |\u000a| 높음 | 자동 모집 마감·취소 | 시작 10분 전 모집 마감. 이 시점에 참가자 2명 미만이면 경주 자동 취소 |\u000a| 높음 | 실시간 GPS 러닝 | 디바이스 GPS로 이동 거리 누적, WebSocket으로 참가자 위치/거리 실시간 동기화 |\u000a| 높음 | 실시간 리더보드 | 경주 중 참가자 순위·거리·페이스를 실시간 표시 |\u000a| 높음 | 등수 판정 | 클라이언트 GPS 기반으로 목표 도달 순서에 따라 등수 확정. 동시 도달 시 공동 순위. 미완주·중도 이탈자는 완주자 뒤 누적 거리순 |\u000a| 보통 | 결과 & 경주 이력 | 경주 종료 후 사용자별 경주 이력에서 결과(등수·거리·시간·페이스) 조회 |\u000a| 낮음 | 경주 중 지도 표시 | 러닝 화면에 본인 경로/지도 표시 (여력 시) |\u000a\u000a> 📌 **참고** — 방(Room)의 상태(모집 중·모집 마감·경기 중·종료·취소)와 전이 규칙은 도메인 문서(`/ib-domain`)에서 엔티티 속성으로 정의한다.\u000a\u000a## 4. 범위 밖 (Out of Scope)\u000a\u000a> ⚠️ **범위 밖** — 이번 1차 MVP에서 하지 않는다.\u000a> - 부정행위 방지 (GPS 스푸핑·차량 이동 탐지 등) — 차기 버전에서 검토\u000a> - GPS 튐(순간 거리 급증) 보정 — 이번 MVP에서는 무시\u000a> - 서버 측 목표 도달 재검증 (MVP는 클라이언트 판정)\u000a> - 소셜 기능 (친구, 팔로우, 채팅)\u000a> - 랭킹/리그/시즌, 리워드·포인트\u000a> - 코스 지정형(특정 경로 완주), 팀전\u000a> - 웨어러블(스마트워치) 연동\u000a> - 자체 이메일/비밀번호 회원가입\u000a\u000a## 5. 비기능 요구사항\u000a\u000a| 항목 | 요구사항/기준 |\u000a| --- | --- |\u000a| 플랫폼 | Flutter 단일 코드베이스로 Android / iOS 동시 지원 |\u000a| 실시간성 | 리더보드/위치 동기화 지연 수 초 이내 (WebSocket) |\u000a| 위치 권한 | 위치 권한(백그라운드 포함)은 필수. 거부 시 앱 사용 불가 처리 |\u000a| 위치 정확도 | GPS 이동 거리 오차 허용 범위 내, 백그라운드 위치 추적 지원 |\u000a| 안정성 | 방 생성 → 경주 완료까지 크래시 없이 완주 가능 |\u000a| 복원력 | 러닝 중 네트워크 단절 시 재연결·거리 재동기화 처리 |\u000a| 인증/보안 | OAuth 기반 소셜 로그인 (카카오/구글/애플) |\u000a| 배터리 | 지속 GPS 추적에도 실사용 가능한 배터리 소모 수준 |\u000a\u000a## 6. 성공 지표\u000a\u000a| 지표 | 목표값 | 측정 방법 |\u000a| --- | --- | --- |\u000a| 경주 완주율 | 시작한 경주의 95% 이상 크래시 없이 결과 도달 | 세션 로그/크래시 리포트 |\u000a| 리더보드 동기화 지연 | 평균 3초 이내 | 서버-클라이언트 타임스탬프 비교 |\u000a| 거리 측정 오차 | 실측 대비 ±5% 이내 | 기준 코스 실측 테스트 |\u000a| 리텐션(참고) | 첫 경주 후 재참여율 측정 | 사용자별 경주 참여 이벤트 |\u000a\u000a## 7. 테스트 시나리오\u000a\u000a| # | 시나리오 | 절차 (핵심 흐름) | 기대 결과 |\u000a| --- | --- | --- | --- |\u000a| 1 | 소셜 로그인 | 앱 실행 → 카카오/구글/애플 중 선택 → 인증 | 로그인 성공, 홈 진입 |\u000a| 2 | 방 생성·입장 | 홈 → 방 생성(거리·시간·정원 입력) → 다른 사용자 입장 | 대기실에 현 인원/정원·참가자 반영, 모집 중 상태 |\u000a| 3 | 방장 조건 수정·강퇴 | 모집 중 방장이 목표 거리 변경, 참가자 강퇴 | 변경 즉시 반영, 강퇴된 사용자 방에서 제거 |\u000a| 4 | 지각 입장 차단 | 모집 마감/경기 중 방에 입장 시도 | 입장 거부 |\u000a| 5 | 자동 취소 | 시작 10분 전(모집 마감) 참가자 1명 | 경주 취소, 참가자에 취소 안내 |\u000a| 6 | 동시 스타트 | 2명 이상 유지 → 시작 시간 도달 | 경기 시작, 참가자 전원 동시 스타트 |\u000a| 7 | 실시간 경주 | 각자 러닝 → 거리 누적 전송 | 리더보드에 실시간 순위·거리 갱신 |\u000a| 8 | 등수 판정 (공동 순위) | 참가자들이 목표 거리 도달, 일부 동시 도달 | 도달 순 등수 확정, 동시 도달자는 공동 순위 |\u000a| 9 | 제한 시간 만료·이탈 | 목표 미도달 또는 중도 이탈 상태로 종료 | 완주자 뒤로 누적 거리순 정렬, 경주 종료 |\u000a| 10 | 경주 이력 확인 | 종료 후 사용자 경주 이력 진입 | 최종 등수·개인 기록(거리/시간/페이스) 표시 |\u000a| 11 | 위치 권한 거부 | 위치 권한 거부/미허용 | 앱 사용 불가 안내 화면 |\u000a\u000a## 8. 핵심 가정 / 미결 질문\u000a\u000a> 📝 **가정 / 미결** — 확정 안 된 사항 및 의도적 단순화. 착수 전 인지 필요.\u000a> - **클라이언트 판정의 신뢰성(의도적 단순화)**: MVP는 목표 도달을 클라이언트 GPS 계산으로 판정하고 GPS 튐도 무시한다. 조작·오차에 취약하므로 차기 버전에서 서버 검증·부정행위 방지로 보완 전제.\u000a> - **백엔드 스택 미정**: 서버 언어/프레임워크, WebSocket 서버, DB 선정 필요.\u000a> - **거리 측정 방식**: 순수 GPS 누적 vs 스텝/센서 융합 — 정확도/배터리 트레이드오프.\u000a> - **동시 시작 정합성**: startTime 기준 클라이언트 시계 오차 보정 방식.\u000a> - **백그라운드 추적 정책**: iOS/Android 백그라운드 위치 권한·배터리 정책 대응.\u000a> - **알림 연동(미결)**: 시작 임박·경주 시작/종료 푸시 알림 범위 (저장소 내 알림 기능 문서와 연계 여부).\u000a> - **진행 중 경주 복귀(미결)**: 앱 강제 종료 후 재실행 시 진행 중 경주 자동 복귀 여부.\u000a> - **가정**: 애플 로그인 포함으로 iOS 소셜 로그인 심사 요건(Sign in with Apple 병행 제공) 충족.\u000a'),'approved',1783508874601,'승인');
INSERT INTO PlanVersion VALUES('cmrctk8im0017rwt4euyos09m','cmrby4wah00021znnga9fbhfq',3,'1차 MVP 기획서',unistr('# 추노\u000a\u000a## 1. 개요 / 목적\u000a\u000a> 🎯 **목적** — 장소에 상관없이, 실시간 GPS로 각자 뛰면서 "누가 목표 거리에 먼저 도달하는가"를 겨루는 경쟁 러닝 앱.\u000a\u000a같은 트랙에 모이지 않아도 방 하나로 원격 러닝 대결이 성립한다. 러닝을 습관화하고 싶지만 동기부여가 부족한 사람에게 "혼자 뛰어도 함께 경쟁하는" 경험을 제공한다. 1차 MVP는 Android/iOS 두 플랫폼을 Flutter 단일 코드베이스로 동시 지원하며, 소셜 로그인 → **최초 온보딩(약관 동의·프로필 설정)** → 방 생성 → 대기 → 실시간 경주 → 등수 판정 → 결과의 한 사이클을 안정적으로 완주시키는 것을 목표로 한다. 위치 정보를 상시 수집하는 서비스 특성상, 최초 가입 시 개인정보·위치기반서비스 약관 동의를 필수로 받는다.\u000a\u000a## 2. 타깃 사용자 & 유스케이스\u000a\u000a| 페르소나 | 니즈 | 핵심 유스케이스 |\u000a| --- | --- | --- |\u000a| 동기부여가 필요한 러너 | 혼자 뛰면 지루하고 꾸준하지 못함 | 친구와 방을 만들어 목표 거리 대결, 이겨서 성취감을 얻는다 |\u000a| 원격의 지인 그룹 | 서로 다른 지역에 살아 같이 못 뜀 | 각자 동네에서 같은 방에 입장해 동시에 스타트, 실시간 순위를 본다 |\u000a| 가벼운 경쟁을 즐기는 사람 | 기록 경쟁·게임성 | 짧은 거리(예: 3km) 방에 참여해 빠르게 승부를 낸다 |\u000a| 신규 가입자 | 안심하고 서비스를 시작하고 싶음 | 최초 로그인 후 약관·개인정보 동의와 닉네임 설정을 마치고 서비스에 진입한다 |\u000a\u000a## 3. 핵심 기능 (MVP)\u000a\u000a| 우선순위 | 기능 | 설명 |\u000a| --- | --- | --- |\u000a| 높음 | 소셜 로그인 | 카카오 / 구글 / 애플 인증으로 가입·로그인 (자체 이메일 가입 없음) |\u000a| 높음 | 온보딩 & 약관 동의 | 최초 가입 시 필수 약관(서비스 이용약관·개인정보 수집·이용·위치기반서비스 이용약관) 동의, 닉네임 설정. 선택 약관(마케팅 수신)은 건너뛰기 가능. 필수 미동의 시 진입 차단 |\u000a| 높음 | 약관 버전 관리·개정 재동의 | 약관은 버전 단위로 관리한다. 필수 약관이 개정되면 재로그인 시 변경된 약관만 재동의 요구 |\u000a| 높음 | 방 생성 | 목표 거리·제한 시간·시작 시간·최대 인원을 설정해 방 개설 |\u000a| 높음 | 방 목록 / 입장 | 모집 중 상태의 방에만 입장 가능. 지각 입장 없음 |\u000a| 높음 | 대기실 & 방장 관리 | 현 인원/정원·참가자 목록·시작 카운트다운·완주 기준 페이스 표시. 모집 중 방장이 목표 거리·제한 시간·최대 인원 수정 및 참가자 강퇴 가능 |\u000a| 높음 | 자동 모집 마감·취소 | 시작 10분 전 모집 마감. 이 시점에 참가자 2명 미만이면 경주 자동 취소 |\u000a| 높음 | 실시간 GPS 러닝 | 디바이스 GPS로 이동 거리 누적, WebSocket으로 참가자 위치/거리 실시간 동기화 |\u000a| 높음 | 실시간 리더보드 | 경주 중 참가자 순위·거리·페이스를 실시간 표시 |\u000a| 높음 | 등수 판정 | 클라이언트 GPS 기반으로 목표 도달 순서에 따라 등수 확정. 동시 도달 시 공동 순위. 미완주·중도 이탈자는 완주자 뒤 누적 거리순 |\u000a| 보통 | 결과 & 경주 이력 | 경주 종료 후 사용자별 경주 이력에서 결과(등수·거리·시간·페이스) 조회 |\u000a\u000a> 📌 **참고** — 방(Room)의 상태와 전이 규칙은 도메인 문서(`/ib-domain`)에서 정의한다. 약관 동의는 **Agreement(약관 마스터: 유형·버전·필수 여부·본문)** 와 **UserConsent(사용자별 동의 이력: 약관·동의 여부·동의 시각)** 도메인으로 관리한다 (정의 완료).\u000a\u000a## 4. 범위 밖 (Out of Scope)\u000a\u000a> ⚠️ **범위 밖** — 이번 1차 MVP에서 하지 않는다.\u000a> - 약관 원문(법무 문안) 작성 자체 — 법무/운영 영역, 기획은 동의 흐름·데이터만 다룸\u000a> - 만 14세 미만 연령 확인·법정대리인 동의 — 이번 MVP에서 제외\u000a> - 소셜 기능 (친구, 팔로우, 채팅)\u000a> - 랭킹/리그/시즌, 리워드·포인트\u000a> - 코스 지정형(특정 경로 완주), 팀전\u000a> - 웨어러블(스마트워치) 연동\u000a> - 자체 이메일/비밀번호 회원가입\u000a\u000a> ➡️ **2차 이관** — 아래 항목은 「2차 MVP 기획서」로 옮겼다: 푸시 알림 · 멀티기기 지원 · 경주 중 지도/경로 표시 · 진행 중 경주 복귀 · 서버 측 목표 도달 재검증 · 부정행위 방지(GPS 스푸핑·차량 이동 탐지) · GPS 튐 보정 · 개인정보 관리 화면(동의 철회·다운로드).\u000a\u000a## 5. 비기능 요구사항\u000a\u000a| 항목 | 요구사항/기준 |\u000a| --- | --- |\u000a| 플랫폼 | Flutter 단일 코드베이스로 Android / iOS 동시 지원 |\u000a| 실시간성 | 리더보드/위치 동기화 지연 수 초 이내 (WebSocket) |\u000a| 개인정보/약관 | 필수 약관 동의 없이는 서비스 이용 불가. 동의 이력(약관 유형·버전·동의 시각)을 보관하고 개인정보보호법·위치정보법을 준수 |\u000a| 위치 권한 | 위치 권한(백그라운드 포함)은 필수. 거부 시 앱 사용 불가 처리 |\u000a| 위치 정확도 | GPS 이동 거리 오차 허용 범위 내, 백그라운드 위치 추적 지원 |\u000a| 안정성 | 방 생성 → 경주 완료까지 크래시 없이 완주 가능 |\u000a| 복원력 | 러닝 중 네트워크 단절 시 재연결·거리 재동기화 처리 |\u000a| 인증/보안 | OAuth 기반 소셜 로그인 (카카오/구글/애플) |\u000a| 배터리 | 지속 GPS 추적에도 실사용 가능한 배터리 소모 수준 |\u000a\u000a## 6. 성공 지표\u000a\u000a| 지표 | 목표값 | 측정 방법 |\u000a| --- | --- | --- |\u000a| 온보딩 완료율 | 로그인 사용자의 90% 이상이 약관 동의·닉네임 설정까지 완료 | 온보딩 단계별 이벤트 로그 |\u000a| 경주 완주율 | 시작한 경주의 95% 이상 크래시 없이 결과 도달 | 세션 로그/크래시 리포트 |\u000a| 리더보드 동기화 지연 | 평균 3초 이내 | 서버-클라이언트 타임스탬프 비교 |\u000a| 거리 측정 오차 | 실측 대비 ±5% 이내 | 기준 코스 실측 테스트 |\u000a| 리텐션(참고) | 첫 경주 후 재참여율 측정 | 사용자별 경주 참여 이벤트 |\u000a\u000a## 7. 테스트 시나리오\u000a\u000a| # | 시나리오 | 절차 (핵심 흐름) | 기대 결과 |\u000a| --- | --- | --- | --- |\u000a| 1 | 소셜 로그인 | 앱 실행 → 카카오/구글/애플 중 선택 → 인증 | 로그인 성공 |\u000a| 2 | 최초 온보딩 | 최초 로그인 → 필수 약관 전체 동의 + 닉네임 입력 → 완료 | 홈 진입, 동의 이력 저장 |\u000a| 3 | 필수 약관 미동의 | 온보딩에서 필수 약관 일부 미동의 상태로 진행 시도 | 진행 버튼 비활성/차단, 진입 불가 |\u000a| 4 | 재로그인 스킵 | 이미 온보딩 완료한 사용자가 재로그인 | 온보딩 생략, 곧바로 홈 |\u000a| 5 | 약관 개정 재동의 | 필수 약관 개정(새 버전) 후 기존 사용자 로그인 | 변경된 약관만 재동의 화면 노출, 동의 후 진입 |\u000a| 6 | 방 생성·입장 | 홈 → 방 생성(거리·시간·정원 입력) → 다른 사용자 입장 | 대기실에 현 인원/정원·참가자 반영, 모집 중 상태 |\u000a| 7 | 방장 조건 수정·강퇴 | 모집 중 방장이 목표 거리 변경, 참가자 강퇴 | 변경 즉시 반영(페이스 재계산), 강퇴된 사용자 방에서 제거 |\u000a| 8 | 지각 입장 차단 | 모집 마감/경기 중 방에 입장 시도 | 입장 거부 |\u000a| 9 | 자동 취소 | 시작 10분 전(모집 마감) 참가자 1명 | 경주 취소, 참가자에 취소 안내 |\u000a| 10 | 동시 스타트 | 2명 이상 유지 → 시작 시간 도달 | 경기 시작, 참가자 전원 동시 스타트 |\u000a| 11 | 실시간 경주 | 각자 러닝 → 거리 누적 전송 | 리더보드에 실시간 순위·거리 갱신 |\u000a| 12 | 등수 판정 (공동 순위) | 참가자들이 목표 거리 도달, 일부 동시 도달 | 도달 순 등수 확정, 동시 도달자는 공동 순위 |\u000a| 13 | 제한 시간 만료·이탈 | 목표 미도달 또는 중도 이탈 상태로 종료 | 완주자 뒤로 누적 거리순 정렬, 경주 종료 |\u000a| 14 | 경주 이력 확인 | 종료 후 사용자 경주 이력 진입 | 최종 등수·개인 기록(거리/시간/페이스) 표시 |\u000a| 15 | 위치 권한 거부 | 위치 권한 거부/미허용 | 앱 사용 불가 안내 화면 |\u000a\u000a## 8. 핵심 가정 / 미결 질문\u000a\u000a> ✅ **확정** — 약관 구성: 필수 = 서비스 이용약관 · 개인정보 수집·이용 동의 · 위치기반서비스 이용약관 / 선택 = 마케팅 정보 수신. (만 14세 이상 확인 제외) · 약관은 **버전 단위로 관리**하고, 개정 시 **변경된 약관만 재동의**. 관련 도메인(Agreement / UserConsent) 정의 완료.\u000a\u000a> 📝 **가정 / 미결** — 확정 안 된 사항 및 의도적 단순화. 착수 전 인지 필요.\u000a> - **약관 원문 확보(미결)**: 실제 약관 문안은 법무 검토 필요 — 기획은 흐름/데이터만 정의.\u000a> - **클라이언트 판정의 신뢰성(의도적 단순화)**: MVP는 목표 도달을 클라이언트 GPS 계산으로 판정하고 GPS 튐도 무시한다. 서버 검증·부정행위 방지·GPS 보정은 2차에서 보완.\u000a> - **백엔드 스택 미정**: 서버 언어/프레임워크, WebSocket 서버, DB 선정 필요.\u000a> - **거리 측정 방식**: 순수 GPS 누적 vs 스텝/센서 융합 — 정확도/배터리 트레이드오프.\u000a> - **동시 시작 정합성**: startTime 기준 클라이언트 시계 오차 보정 방식.\u000a> - **백그라운드 추적 정책**: iOS/Android 백그라운드 위치 권한·배터리 정책 대응.\u000a> - **가정**: 애플 로그인 포함으로 iOS 소셜 로그인 심사 요건(Sign in with Apple 병행 제공) 충족.\u000a\u000a---\u000a### 진행 메모 (2026-07-09) — 1차 확정 스코프\u000a\u000a**입장 / 재동의**\u000a- 방 입장은 **공개 방 목록 입장 전용** (초대 코드·비공개 방 없음 — Room에 inviteCode 미도입).\u000a- 약관 **개정 재동의는 프로필 화면**에서 처리 (온보딩과 별도). `data-screen=profile`, `[Onboarding] 약관 버전 관리·재동의` 이슈를 profile에 연동.\u000a\u000a**경주 실행 (에픽 A~D)**\u000a- **판정 = 서버 릴레이(클라이언트 판정)**: 각 클라이언트가 GPS로 거리·목표 도달을 계산해 전송, 서버는 재계산 없이 도달/진행 순서만 확정. **원시 GPS 좌표 미보존**(TrackPoint 미도입) — 진행값은 `Participant.currentDistance`로만 전송.\u000a- **동시 스타트 = 서버 시각 기준**: 서버가 "start at T / ends at T+limit" 신호를 WS로 브로드캐스트, 클라이언트는 서버 시각 오프셋으로 카운트다운·종료.\u000a- **미완주·중도 이탈·앱 강제 종료 = dnf** → 완주자 뒤 누적 거리순.\u000a- **단일 기기 전제**(멀티기기 미지원), **푸시 알림 없음** → 대기실에서 앱을 열어둔 채 카운트다운하는 흐름을 전제로 한다.\u000a\u000a**2차로 이관됨** (→ 「2차 MVP 기획서」): 푸시 알림 · 멀티기기 지원 · 경주 중 지도/경로 표시(TrackPoint 재도입) · 진행 중 경주 복귀 · 서버 측 목표 도달 재검증 · 부정행위 방지 · GPS 튐 보정 · 개인정보 관리 화면.'),'approved',1783559980318,'최종본');
CREATE TABLE IF NOT EXISTS "Wireframe" (
    "id" TEXT NOT NULL PRIMARY KEY,
    "projectId" TEXT NOT NULL,
    "name" TEXT NOT NULL,
    "format" TEXT NOT NULL DEFAULT 'html',
    "content" TEXT NOT NULL,
    "sequence" INTEGER NOT NULL DEFAULT 0,
    "version" INTEGER NOT NULL DEFAULT 1,
    "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT "Wireframe_projectId_fkey" FOREIGN KEY ("projectId") REFERENCES "Project" ("id") ON DELETE CASCADE ON UPDATE CASCADE
);
INSERT INTO Wireframe VALUES('cmrc09bag00091z187dj593eb','cmrby3y0000001znnofoo0a53','로그인','html',unistr('<!doctype html><html><head><meta charset="utf-8"><style>\u000a:root{--wf-bg:#f4f4f5;--wf-surface:#fff;--wf-line:#d4d4d8;--wf-ink:#3f3f46;--wf-muted:#a1a1aa;--wf-fill:#e4e4e7;--wf-radius:10px;--wf-gap:12px;}\u000a*{box-sizing:border-box;margin:0;padding:0}\u000abody{background:var(--wf-bg);color:var(--wf-ink);font-size:14px;line-height:1.5;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',sans-serif;display:flex;justify-content:center;padding:16px}\u000a.wf{width:100%;max-width:390px;min-height:720px;background:var(--wf-surface);border:1px solid var(--wf-line);border-radius:20px;overflow:hidden;display:flex;flex-direction:column}\u000a.wf-topbar{display:flex;align-items:center;gap:8px;padding:14px 16px;border-bottom:1px solid var(--wf-line);font-weight:600}\u000a.wf-body{flex:1;padding:16px;display:flex;flex-direction:column;gap:var(--wf-gap)}\u000a.wf-title{font-size:18px;font-weight:700}\u000a.wf-sub{color:var(--wf-muted);font-size:13px}\u000a.wf-card{border:1px solid var(--wf-line);border-radius:var(--wf-radius);padding:14px}\u000a.wf-ph{background:var(--wf-fill);border-radius:8px}\u000a.wf-input{width:100%;border:1px solid var(--wf-line);border-radius:8px;padding:10px 12px;background:var(--wf-surface);font:inherit}\u000a.wf-btn{border:1px solid var(--wf-line);border-radius:8px;padding:10px 14px;background:var(--wf-surface);cursor:pointer;font:inherit}\u000a.wf-btn-primary{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.wf-list{display:flex;flex-direction:column}\u000a.wf-list-item{display:flex;align-items:center;gap:10px;padding:12px 0;border-bottom:1px solid var(--wf-line)}\u000a.wf-avatar{flex:0 0 auto;width:36px;height:36px;border-radius:50%;background:var(--wf-fill)}\u000a.wf-badge{font-size:11px;padding:2px 8px;border-radius:999px;background:var(--wf-fill);color:var(--wf-muted)}\u000a.wf-tabbar{display:flex;border-top:1px solid var(--wf-line)}\u000a.wf-tabbar button{flex:1;padding:12px;border:none;background:none;color:var(--wf-muted);cursor:pointer;font:inherit}\u000a.wf-tabbar button.active{color:var(--wf-ink);font-weight:600}\u000a</style></head>\u000a<body data-screen="login">\u000a<div class="wf">\u000a <header class="wf-topbar">추노</header>\u000a <main class="wf-body" style="justify-content:center;text-align:center">\u000a   <div class="wf-ph" style="width:96px;height:96px;border-radius:24px;margin:0 auto"></div>\u000a   <div class="wf-title">장소 무관 경쟁 러닝</div>\u000a   <div class="wf-sub">방을 만들어 목표 거리를 먼저 완주하세요</div>\u000a   <div style="height:16px"></div>\u000a   <button class="wf-btn" data-p="카카오">카카오로 시작</button>\u000a   <button class="wf-btn" data-p="구글">구글로 시작</button>\u000a   <button class="wf-btn" data-p="Apple">Apple로 시작</button>\u000a   <div id="msg" class="wf-sub" style="min-height:18px"></div>\u000a </main>\u000a</div>\u000a<script>\u000adocument.querySelectorAll(''[data-p]'').forEach(function(b){\u000a  b.addEventListener(''click'',function(){\u000a    document.querySelectorAll(''[data-p]'').forEach(function(x){x.classList.remove(''wf-btn-primary'')});\u000a    b.classList.add(''wf-btn-primary'');\u000a    var m=document.getElementById(''msg''),p=b.getAttribute(''data-p'');\u000a    m.textContent=p+'' 인증 중…'';\u000a    setTimeout(function(){m.textContent=p+'' 로그인 완료 ✓'';},700);\u000a  });\u000a});\u000a</script>\u000a</body></html>'),1,1,1783510761832);
INSERT INTO Wireframe VALUES('cmrc0a433000d1z188fcz9jya','cmrby3y0000001znnofoo0a53','방 생성','html',unistr('<!doctype html><html><head><meta charset="utf-8"><style>\u000a:root{--wf-bg:#f4f4f5;--wf-surface:#fff;--wf-line:#d4d4d8;--wf-ink:#3f3f46;--wf-muted:#a1a1aa;--wf-fill:#e4e4e7;--wf-radius:10px;--wf-gap:12px;}\u000a*{box-sizing:border-box;margin:0;padding:0}\u000abody{background:var(--wf-bg);color:var(--wf-ink);font-size:14px;line-height:1.5;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',sans-serif;display:flex;justify-content:center;padding:16px}\u000a.wf{width:100%;max-width:390px;min-height:720px;background:var(--wf-surface);border:1px solid var(--wf-line);border-radius:20px;overflow:hidden;display:flex;flex-direction:column}\u000a.wf-topbar{display:flex;align-items:center;gap:8px;padding:14px 16px;border-bottom:1px solid var(--wf-line);font-weight:600}\u000a.wf-body{flex:1;padding:16px;display:flex;flex-direction:column;gap:var(--wf-gap);overflow:auto}\u000a.wf-title{font-size:18px;font-weight:700}\u000a.wf-sub{color:var(--wf-muted);font-size:13px}\u000a.wf-card{border:1px solid var(--wf-line);border-radius:var(--wf-radius);padding:14px}\u000a.wf-ph{background:var(--wf-fill);border-radius:8px}\u000a.wf-input{width:100%;border:1px solid var(--wf-line);border-radius:8px;padding:10px 12px;background:var(--wf-surface);font:inherit}\u000a.wf-btn{border:1px solid var(--wf-line);border-radius:8px;padding:10px 14px;background:var(--wf-surface);cursor:pointer;font:inherit}\u000a.wf-btn-primary{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.wf-list{display:flex;flex-direction:column}\u000a.wf-list-item{display:flex;align-items:center;gap:10px;padding:12px 0;border-bottom:1px solid var(--wf-line)}\u000a.wf-avatar{flex:0 0 auto;width:36px;height:36px;border-radius:50%;background:var(--wf-fill)}\u000a.wf-badge{font-size:11px;padding:2px 8px;border-radius:999px;background:var(--wf-fill);color:var(--wf-muted)}\u000a.wf-chip{border:1px solid var(--wf-line);border-radius:999px;padding:6px 12px;background:var(--wf-surface);cursor:pointer;font:inherit}\u000a.wf-chip.on{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.wf-field{display:flex;flex-direction:column;gap:6px}\u000a.wf-label{font-size:13px;font-weight:600}\u000a</style></head>\u000a<body data-screen="room-create">\u000a<div class="wf">\u000a <header class="wf-topbar">← 방 만들기</header>\u000a <form class="wf-body" id="f">\u000a   <div class="wf-field"><span class="wf-label">방 제목</span><input class="wf-input" placeholder="예: 아침 3km 대결"></div>\u000a   <div class="wf-field"><span class="wf-label">목표 거리</span>\u000a     <div style="display:flex;gap:8px;flex-wrap:wrap" id="dist">\u000a       <button type="button" class="wf-chip" data-v="2">2km</button>\u000a       <button type="button" class="wf-chip on" data-v="3">3km</button>\u000a       <button type="button" class="wf-chip" data-v="5">5km</button>\u000a       <button type="button" class="wf-chip" data-v="10">10km</button>\u000a     </div>\u000a   </div>\u000a   <div class="wf-field"><span class="wf-label">제한 시간 (분)</span><input class="wf-input" type="number" value="30"></div>\u000a   <div class="wf-field"><span class="wf-label">시작 시간</span><input class="wf-input" placeholder="2026-07-09 07:00:00"></div>\u000a   <div class="wf-field"><span class="wf-label">최대 인원</span>\u000a     <div style="display:flex;align-items:center;gap:14px">\u000a       <button type="button" class="wf-btn" id="minus">−</button>\u000a       <b id="cap" style="font-size:18px;min-width:24px;text-align:center">6</b>\u000a       <button type="button" class="wf-btn" id="plus">+</button>\u000a     </div>\u000a   </div>\u000a   <button class="wf-btn wf-btn-primary" type="submit">방 개설</button>\u000a   <div class="wf-card" id="summary" style="display:none"></div>\u000a </form>\u000a</div>\u000a<script>\u000adocument.querySelectorAll(''#dist .wf-chip'').forEach(function(c){\u000a  c.addEventListener(''click'',function(){\u000a    document.querySelectorAll(''#dist .wf-chip'').forEach(function(x){x.classList.remove(''on'')});\u000a    c.classList.add(''on'');\u000a  });\u000a});\u000avar cap=6,capEl=document.getElementById(''cap'');\u000adocument.getElementById(''plus'').onclick=function(){if(cap<20){cap++;capEl.textContent=cap;}};\u000adocument.getElementById(''minus'').onclick=function(){if(cap>2){cap--;capEl.textContent=cap;}};\u000adocument.getElementById(''f'').addEventListener(''submit'',function(e){\u000a  e.preventDefault();\u000a  var d=document.querySelector(''#dist .on'').getAttribute(''data-v'');\u000a  var s=document.getElementById(''summary'');\u000a  s.style.display=''block'';\u000a  s.innerHTML=''<b>개설 확인</b><div class="wf-sub">목표 ''+d+''km · 최대 ''+cap+''명 · 상태 모집 중으로 생성됩니다</div>'';\u000a});\u000a</script>\u000a</body></html>'),3,1,1783510799151);
