nt-weight:600}\u000a</style></head>\u000a<body data-screen="waiting-room">\u000a<div class="wf">\u000a <header class="wf-topbar">← 대기실</header>\u000a <main class="wf-body">\u000a   <div style="display:flex;justify-content:space-between;align-items:center">\u000a     <div class="wf-title">아침 3km 대결</div><span class="wf-badge">모집 중</span>\u000a   </div>\u000a   <div class="wf-card" style="text-align:center">\u000a     <div class="wf-sub">시작까지</div>\u000a     <div style="font-size:28px;font-weight:700" id="cd">09:58</div>\u000a     <div class="wf-sub">목표 3km · 제한 30분</div>\u000a   </div>\u000a   <div style="display:flex;justify-content:space-between;align-items:center">\u000a     <span class="wf-label">참가자</span><span class="wf-sub" id="count">3 / 6</span>\u000a   </div>\u000a   <div class="wf-list" id="plist">\u000a     <div class="wf-list-item"><div class="wf-avatar"></div><b style="flex:1">나 (방장)</b><span class="wf-badge">HOST</span></div>\u000a     <div class="wf-list-item"><div class="wf-avatar"></div><span style="flex:1">러너_김</span><button class="wf-btn kick" style="padding:4px 10px;font-size:12px">강퇴</button></div>\u000a     <div class="wf-list-item"><div class="wf-avatar"></div><span style="flex:1">러너_이</span><button class="wf-btn kick" style="padding:4px 10px;font-size:12px">강퇴</button></div>\u000a   </div>\u000a   <button class="wf-btn" id="editToggle">조건 수정 (방장)</button>\u000a   <div class="wf-card" id="editBox" style="display:none">\u000a     <div class="wf-label" style="margin-bottom:8px">조건 수정 — 모집 중에만 가능</div>\u000a     <input class="wf-input" style="margin-bottom:8px" value="목표 3km">\u000a     <input class="wf-input" style="margin-bottom:8px" value="제한 30분">\u000a     <input class="wf-input" value="최대 6명">\u000a   </div>\u000a   <div style="flex:1"></div>\u000a   <button class="wf-btn wf-btn-primary" disabled style="opacity:.6">시작 시간에 자동 시작</button>\u000a </main>\u000a</div>\u000a<script>\u000avar t=598,cd=document.getElementById(''cd'');\u000asetInterval(function(){ if(t>0){t--; var m=String(Math.floor(t/60)).padStart(2,''0''),s=String(t%60).padStart(2,''0''); cd.textContent=m+'':''+s;} },1000);\u000afunction refresh(){\u000a  var n=document.querySelectorAll(''#plist .wf-list-item'').length;\u000a  document.getElementById(''count'').textContent=n+'' / 6'';\u000a}\u000adocument.querySelectorAll(''.kick'').forEach(function(b){\u000a  b.addEventListener(''click'',function(){ b.closest(''.wf-list-item'').remove(); refresh(); });\u000a});\u000adocument.getElementById(''editToggle'').addEventListener(''click'',function(){\u000a  var e=document.getElementById(''editBox'');\u000a  var open=e.style.display===''none'';\u000a  e.style.display=open?''block'':''none'';\u000a  this.classList.toggle(''wf-btn-primary'',open);\u000a});\u000a</script>\u000a</body></html>'),4,1,1783510832933);
INSERT INTO Wireframe VALUES('cmrc0b903000h1z18bf2lnqec','cmrby3y0000001znnofoo0a53','러닝 (실시간 리더보드)','html',unistr('<!doctype html><html><head><meta charset="utf-8"><style>\u000a:root{--wf-bg:#f4f4f5;--wf-surface:#fff;--wf-line:#d4d4d8;--wf-ink:#3f3f46;--wf-muted:#a1a1aa;--wf-fill:#e4e4e7;--wf-radius:10px;--wf-gap:12px;}\u000a*{box-sizing:border-box;margin:0;padding:0}\u000abody{background:var(--wf-bg);color:var(--wf-ink);font-size:14px;line-height:1.5;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',sans-serif;display:flex;justify-content:center;padding:16px}\u000a.wf{width:100%;max-width:390px;min-height:720px;background:var(--wf-surface);border:1px solid var(--wf-line);border-radius:20px;overflow:hidden;display:flex;flex-direction:column}\u000a.wf-topbar{display:flex;align-items:center;gap:8px;padding:14px 16px;border-bottom:1px solid var(--wf-line);font-weight:600}\u000a.wf-body{flex:1;padding:16px;display:flex;flex-direction:column;gap:var(--wf-gap);overflow:auto}\u000a.wf-title{font-size:18px;font-weight:700}\u000a.wf-sub{color:var(--wf-muted);font-size:13px}\u000a.wf-card{border:1px solid var(--wf-line);border-radius:var(--wf-radius);padding:14px}\u000a.wf-ph{background:var(--wf-fill);border-radius:8px}\u000a.wf-btn{border:1px solid var(--wf-line);border-radius:8px;padding:10px 14px;background:var(--wf-surface);cursor:pointer;font:inherit}\u000a.wf-btn-primary{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.wf-list{display:flex;flex-direction:column}\u000a.wf-list-item{display:flex;align-items:center;gap:10px;padding:12px 0;border-bottom:1px solid var(--wf-line)}\u000a.wf-badge{font-size:11px;padding:2px 8px;border-radius:999px;background:var(--wf-fill);color:var(--wf-muted)}\u000a.wf-rank{width:22px;text-align:center;font-weight:700}\u000a.wf-bar{height:8px;background:var(--wf-fill);border-radius:999px;overflow:hidden}\u000a.wf-bar>i{display:block;height:100%;background:var(--wf-ink);width:0}\u000a</style></head>\u000a<body data-screen="race">\u000a<div class="wf">\u000a <header class="wf-topbar">경기 중 · 아침 3km 대결</header>\u000a <main class="wf-body">\u000a   <div class="wf-card" style="text-align:center">\u000a     <div class="wf-sub">내 거리 (목표 3.0km)</div>\u000a     <div style="font-size:30px;font-weight:700"><span id="myd">0.00</span> km</div>\u000a     <div class="wf-bar" style="margin:8px 0"><i id="mybar"></i></div>\u000a     <div class="wf-sub">페이스 <span id="pace">--</span> /km · 남은시간 <span id="rt">30:00</span></div>\u000a   </div>\u000a   <div class="wf-ph" style="height:90px;display:flex;align-items:center;justify-content:center;color:var(--wf-muted)">지도 / 경로 (저해상도)</div>\u000a   <div style="display:flex;justify-content:space-between;align-items:center">\u000a     <span class="wf-title" style="font-size:15px">실시간 순위</span><span class="wf-sub" id="live">● LIVE</span>\u000a   </div>\u000a   <div class="wf-list" id="board"></div>\u000a   <div style="flex:1"></div>\u000a   <button class="wf-btn" id="quit">경주 포기</button>\u000a   <div id="msg" class="wf-sub" style="text-align:center;min-height:16px"></div>\u000a </main>\u000a</div>\u000a<script>\u000avar goal=3.0;\u000avar runners=[{n:''나'',d:0,me:true},{n:''러너_김'',d:0.1},{n:''러너_이'',d:0.05},{n:''러너_박'',d:0.08}];\u000avar board=document.getElementById(''board'');\u000afunction render(){\u000a  var sorted=runners.slice().sort(function(a,b){return b.d-a.d});\u000a  board.innerHTML='''';\u000a  sorted.forEach(function(r,i){\u000a    var row=document.createElement(''div''); row.className=''wf-list-item'';\u000a    row.innerHTML=''<span class="wf-rank">''+(i+1)+''</span><span style="flex:1">''+r.n+(r.me?'' <span class=\\"wf-badge\\">나</span>'':'''')+''</span><b>''+r.d.toFixed(2)+'' km</b>'';\u000a    if(r.me) row.style.background=''var(--wf-fill)'';\u000a    board.appendChild(row);\u000a  });\u000a  var me=runners[0];\u000a  document.getElementById(''myd'').textContent=me.d.toFixed(2);\u000a  document.getElementById(''mybar'').style.width=Math.min(100,me.d/goal*100)+''%'';\u000a  document.getElementById(''pace'').textContent=me.d>0?(6+ (0.5-0)).toFixed(1).replace(''.'',"''")+''"'':"--";\u000a}\u000avar tick=setInterval(function(){\u000a  runners.forEach(function(r){ if(r.d<goal) r.d+=Math.random()*0.04+0.01; });\u000a  render();\u000a  var done=runners[0].d>=goal;\u000a  if(runners.some(function(r){return r.d>=goal})){\u000a    var first=runners.slice().sort(function(a,b){return b.d-a.d})[0];\u000a    if(first.d>=goal){ document.getElementById(''live'').textContent=''● 완주자 발생''; }\u000a  }\u000a  if(runners.every(function(r){return r.d>=goal})){ clearInterval(tick); document.getElementById(''live'').textContent=''경기 종료''; }\u000a},900);\u000arender();\u000adocument.getElementById(''quit'').addEventListener(''click'',function(){\u000a  clearInterval(tick); document.getElementById(''msg'').textContent=''포기 처리 — 완주자 뒤 거리순으로 기록됩니다'';\u000a  this.classList.add(''wf-btn-primary'');\u000a});\u000a</script>\u000a</body></html>'),5,1,1783510852180);
