arttime{font-size:12px;color:var(--wf-ink);font-weight:600;display:flex;align-items:center;gap:4px}\u000a.rowtop{display:flex;justify-content:space-between;align-items:center;gap:8px}\u000a.meta{display:flex;justify-content:space-between;align-items:center;margin-top:6px;gap:8px}\u000a/* 필터 아이콘 버튼 */\u000a.icon-btn{display:flex;align-items:center;justify-content:center;width:38px;height:38px;padding:0;color:var(--wf-ink);position:relative}\u000a.icon-btn.wf-btn-primary{color:#fff}\u000a.icon-btn .dot{position:absolute;top:-3px;right:-3px;width:9px;height:9px;border-radius:50%;background:var(--wf-ink);border:2px solid var(--wf-surface);display:none}\u000a.icon-btn .dot.on{display:block}\u000a/* 필터 패널 */\u000a.frow{display:flex;justify-content:space-between;align-items:center}\u000a.chip-toggle{font-size:12px;padding:6px 12px;border-radius:999px;border:1px solid var(--wf-line);background:var(--wf-surface);cursor:pointer}\u000a.chip-toggle.on{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.range{position:relative;height:34px;margin-top:6px}\u000a.range .track{position:absolute;left:0;right:0;top:14px;height:6px;background:var(--wf-fill);border-radius:999px}\u000a.range .fill{position:absolute;top:0;height:100%;background:var(--wf-ink);border-radius:999px}\u000a.range input[type=range]{position:absolute;left:0;top:0;width:100%;height:34px;margin:0;background:none;pointer-events:none;-webkit-appearance:none;appearance:none}\u000a.range input[type=range]::-webkit-slider-thumb{-webkit-appearance:none;pointer-events:auto;width:18px;height:18px;border-radius:50%;background:var(--wf-ink);border:2px solid #fff;box-shadow:0 0 0 1px var(--wf-line);cursor:pointer}\u000a.range input[type=range]::-moz-range-thumb{pointer-events:auto;width:18px;height:18px;border-radius:50%;background:var(--wf-ink);border:2px solid #fff;cursor:pointer}\u000a/* 하단 플로팅: 좌측 초대하기 / 우측 + 방 만들기 */\u000a.fab{position:absolute;right:16px;bottom:74px;width:54px;height:54px;border-radius:50%;background:var(--wf-ink);color:#fff;border:none;font-size:28px;line-height:1;cursor:pointer;box-shadow:0 4px 12px rgba(0,0,0,.22);display:flex;align-items:center;justify-content:center}\u000a.invite-fab{position:absolute;left:16px;bottom:82px;display:flex;align-items:center;gap:6px;border:1px solid var(--wf-line);border-radius:999px;padding:10px 16px;background:var(--wf-surface);cursor:pointer;box-shadow:0 2px 8px rgba(0,0,0,.1);font:inherit;font-weight:600}\u000a/* 모달 */\u000a.modal{position:absolute;inset:0;background:rgba(0,0,0,.35);display:none;align-items:flex-end;justify-content:center}\u000a.modal.show{display:flex}\u000a.sheet{background:var(--wf-surface);width:100%;border-radius:16px 16px 0 0;padding:18px 16px 24px;display:flex;flex-direction:column;gap:12px}\u000a</style></head>\u000a<body data-screen="home">\u000a<div class="wf">\u000a <header class="wf-topbar">홈</header>\u000a <main class="wf-body">\u000a   <div class="frow">\u000a     <div class="wf-title">참여 가능한 방</div>\u000a     <button class="wf-btn icon-btn" id="filterBtn" aria-label="필터" title="필터">\u000a       <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round">\u000a         <line x1="4" y1="7" x2="20" y2="7"/><circle cx="9" cy="7" r="2.6" fill="var(--wf-surface)"/>\u000a         <line x1="4" y1="12" x2="20" y2="12"/><circle cx="15" cy="12" r="2.6" fill="var(--wf-surface)"/>\u000a         <line x1="4" y1="17" x2="20" y2="17"/><circle cx="8" cy="17" r="2.6" fill="var(--wf-surface)"/>\u000a       </svg>\u000a       <span class="dot" id="filterDot"></span>\u000a     </button>\u000a   </div>\u000a\u000a   <!-- 필터 패널 -->\u000a   <div class="wf-card" id="filterPanel" style="display:none">\u000a     <div class="frow">\u000a       <b style="font-size:13px">모집 상태</b>\u000a       <button class="chip-toggle" id="onlyRec">모집 중만</button>\u000a     </div>\u000a     <div style="margin-top:14px">\u000a       <div class="frow"><b style="font-size:13px">거리</b><span class="wf-sub" id="distLabel">0 ~ 12 km</span></div>\u000a       <div class="range" data-key="dist" data-min="0" data-max="12" data-step="1" data-unit="km">\u000a         <div class="track"><div class="fill"></div></div>\u000a         <input type="range" class="lo" min="0" max="12" step="1" value="0">\u000a         <input type="range" class="hi" min="0" max="12" step="1" value="12">\u000a       </div>\u000a     </div>\u000a     <div style="margin-top:10px">\u000a       <div class="frow"><b style="font-size:13px">제한 시간</b><span class="wf-sub" id="timeLabel">0 ~ 120 분</span></div>\u000a       <div class="range" data-key="time" data-min="0" data-max="120" data-step="5" data-unit="분">\u000a         <div class="track"><div class="fill"></div></div>\u000a         <input type="range" class="lo" min="0" max="120" step="5" value="0">\u000a         <input type="range" class="hi" min="0" max="120" step="5" value="120">\u000a       </div>\u000a     </div>\u000a     <div class="frow" style="margin-top:14px">\u000a       <span class="wf-sub" id="count">5개 방</span>\u000a       <button class="wf-btn" id="reset" style="padding:6px 12px;font-size:12px">초기화</button>\u000a     </div>\u000a   </div>\u000a\u000a   <div class="wf-list" id="rooms">\u000a     <div class="wf-card room" data-status="recruiting" data-start="7800" data-dist="3" data-limit="30" style="cursor:pointer">\u000a       <div class="rowtop"><b>아침 3km 대결</b><span class="wf-badge">모집 중</span></div>\u000a       <div class="wf-sub" style="margin-top:6px">목표 3km · 30분 · 정원 2/6</div>\u000a       <div class="meta"><span class="starttime"></span><span class="startin"></span></div>\u000a     </div>\u000a     <div class="wf-card room" data-status="recruiting" data-start="2700" data-dist="10" data-limit="90" style="cursor:pointer;margin-top:10px">\u000a       <div class="rowtop"><b>주말 10km 롱런</b><span class="wf-badge">모집 중</span></div>\u000a       <div class="wf-sub" style="margin-top:6px">목표 10km · 90분 · 정원 1/8</div>\u000a       <div class="meta"><span class="starttime"></span><span class="startin"></span></div>\u000a     </div>\u000a     <div class="wf-card room" data-status="recruiting" data-start="240" data-dist="2" data-limit="20" style="cursor:pointer;margin-top:10px">\u000a       <div class="rowtop"><b>번개 2km 스프린트</b><span class="wf-badge">모집 중</span></div>\u000a       <div class="wf-sub" style="margin-top:6px">목표 2km · 20분 · 정원 3/5</div>\u000a       <div class="meta"><span class="starttime"></span><span class="startin"></span></div>\u000a     </div>\u000a     <div class="wf-card room" data-status="closed" data-start="480" data-dist="5" data-limit="45" style="cursor:pointer;margin-top:10px">\u000a       <div class="rowtop"><b>퇴근런 5km</b><span class="wf-badge">모집 마감</span></div>\u000a       <div class="wf-sub" style="margin-top:6px">목표 5km · 45분 · 정원 4/4</div>\u000a       <div class="meta"><span class="starttime"></span><span class="startin"></span></div>\u000a     </div>\u000a     <div class="wf-card room" data-status="live" data-dist="3" data-limit="30" style="cursor:pointer;margin-top:10px">\u000a       <div class="rowtop"><b>새벽 3km</b><span class="wf-badge">경기 중</span></div>\u000a       <div class="wf-sub" style="margin-top:6px">목표 3km · 30분 · 정원 5/5</div>\u000a       <div class="meta"><span class="starttime">🏃 경기 중</span><span class="startin">12:04 경과</span></div>\u000a     </div>\u000a   </div>\u000a   <div id="empty" class="wf-sub" style="display:none;text-align:center;padding:24px 0">조건에 맞는 방이 없어요</div>\u000a   <div id="note" class="wf-sub" style="text-align:center;min-height:16px"></div>\u000a   <div style="height:72px;flex:0 0 auto"></div>\u000a </main>\u000a\u000a <!-- 하단 플로팅 액션 -->\u000a <button class="invite-fab" id="inviteBtn">🔑 초대하기</button>\u000a <button class="fab" id="createBtn" aria-label="방 만들기" title="방 만들기">+</button>\u000a\u000a <!-- 초대 코드 모달 -->\u000a <div class="modal" id="inviteModal">\u000a   <div class="sheet">\u000a     <b style="font-size:15px">초대 코드로 참가</b>\u000a     <div class="wf-sub">방장에게 받은 6자리 코드를 입력하세요</div>\u000a     <input class="wf-input" id="codeInput" placeholder="예: RUN421" style="text-align:center;letter-spacing:3px;font-weight:700">\u000a     <div style="display:flex;gap:8px">\u000a       <button class="wf-btn" id="invCancel" style="flex:1">취소</button>\u000a       <button class="wf-btn wf-btn-primary" id="invGo" style="flex:1">입장하기</button>\u000a     </div>\u000a   </div>\u000a </div>\u000a\u000a <nav class="wf-tabbar"><button class="active">홈</button><button>이력</button><button>내 정보</button></nav>\u000a</div>\u000a<script>\u000afunction two(n){return (n<10?''0'':'''')+n;}\u000afunction absLabel(ts){var d=new Date(ts),h=d.getHours(),m=d.getMinutes();var ap=h<12?''오전'':''오후'',h12=h%12;if(h12===0)h12=12;return ap+'' ''+h12+'':''+two(m);}\u000afunction relLabel(sec){if(sec<=0)return ''곧 시작'';if(sec>=3600){var h=Math.floor(sec/3600),m=Math.floor((sec%3600)/60);return h+''시간 ''+(m>0?m+''분 '':'''')+''후'';}return Math.ceil(sec/60)+''분 후'';}\u000avar startCards=[].slice.call(document.querySelectorAll(''.room[data-start]''));\u000astartCards.forEach(function(c){c._target=Date.now()+parseInt(c.getAttribute(''data-start''),10)*1000;});\u000afunction paintStart(){startCards.forEach(function(c){var sec=Math.round((c._target-Date.now())/1000);c.querySelector(''.starttime'').innerHTML=''🕘 <b>''+absLabel(c._target)+''</b> 시작'';c.querySelector(''.startin'').textContent=relLabel(sec);});}\u000apaintStart();setInterval(paintStart,1000);\u000a\u000avar state={onlyRec:false,dist:[0,12],time:[0,120]};\u000avar BOUND={dist:[0,12],time:[0,120]};\u000afunction initRange(box,key){\u000a  var lo=box.querySelector(''.lo''),hi=box.querySelector(''.hi''),fill=box.querySelector(''.fill'');\u000a  var mn=+box.dataset.min,mx=+box.dataset.max,unit=box.dataset.unit;\u000a  var label=document.getElementById(key+''Label'');\u000a  function upd(){\u000a    var a=+lo.value,b=+hi.value;\u000a    if(a>b){ if(this===lo){b=a;hi.value=a;} else {a=b;lo.value=b;} }\u000a    state[key]=[a,b];\u000a    var l=(a-mn)/(mx-mn)*100, r=(b-mn)/(mx-mn)*100;\u000a    fill.style.left=l+''%''; fill.style.width=(r-l)+''%'';\u000a    label.textContent=a+'' ~ ''+b+'' ''+unit;\u000a    applyFilter();\u000a  }\u000a  lo.addEventListener(''input'',upd);hi.addEventListener(''input'',upd);\u000a  box._reset=function(){lo.value=mn;hi.value=mx;upd();};\u000a  upd();\u000a}\u000avar boxes={dist:document.querySelector(''.range[data-key=dist]''),time:document.querySelector(''.range[data-key=time]'')};\u000ainitRange(boxes.dist,''dist'');initRange(boxes.time,''time'');\u000a\u000afunction isActive(){return state.onlyRec||state.dist[0]!==BOUND.dist[0]||state.dist[1]!==BOUND.dist[1]||state.time[0]!==BOUND.time[0]||state.time[1]!==BOUND.time[1];}\u000afunction applyFilter(){\u000a  var shown=0;\u000a  document.querySelectorAll(''#rooms .room'').forEach(function(c){\u000a    var d=+c.getAttribute(''data-dist''), t=+c.getAttribute(''data-limit'');\u000a    var ok=(!state.onlyRec || c.getAttribute(''data-status'')===''recruiting'') && d>=state.dist[0] && d<=state.dist[1] && t>=state.time[0] && t<=state.time[1];\u000a    c.style.display=ok?'''':''none''; if(ok)shown++;\u000a  });\u000a  document.getElementById(''count'').textContent=shown+''개 방'';\u000a  document.getElementById(''empty'').style.display=shown?''none'':''block'';\u000a  document.getElementById(''filterDot'').classList.toggle(''on'',isActive());\u000a}\u000a\u000adocument.getElementById(''filterBtn'').addEventListener(''click'',function(){\u000a  var p=document.getElementById(''filterPanel'');var open=p.style.display===''none'';\u000a  p.style.display=open?''block'':''none''; this.classList.toggle(''wf-btn-primary'',open);\u000a});\u000adocument.getElementById(''onlyRec'').addEventListener(''click'',function(){state.onlyRec=!state.onlyRec;this.classList.toggle(''on'',state.onlyRec);applyFilter();});\u000adocument.getElementById(''reset'').addEventListener(''click'',function(){state.onlyRec=false;document.getElementById(''onlyRec'').classList.remove(''on'');boxes.dist._reset();boxes.time._reset();});\u000a\u000adocument.querySelectorAll(''#rooms .room'').forEach(function(c){\u000a  c.addEventListener(''click'',function(){document.querySelectorAll(''#rooms .room'').forEach(function(x){x.style.borderColor=''var(--wf-line)''});c.style.borderColor=''var(--wf-ink)'';});\u000a});\u000adocument.querySelectorAll(''.wf-tabbar button'').forEach(function(b){\u000a  b.addEventListener(''click'',function(){document.querySelectorAll(''.wf-tabbar button'').forEach(function(x){x.classList.remove(''active'')});b.classList.add(''active'');});\u000a});\u000a\u000a// 하단 액션\u000avar im=document.getElementById(''inviteModal'');\u000adocument.getElementById(''inviteBtn'').addEventListener(''click'',function(){im.classList.add(''show'');});\u000adocument.getElementById(''invCancel'').addEventListener(''click'',function(){im.classList.remove(''show'');});\u000adocument.getElementById(''invGo'').addEventListener(''click'',function(){\u000a  var v=document.getElementById(''codeInput'').value.trim();\u000a  im.classList.remove(''show'');\u000a  document.getElementById(''note'').textContent=v?(''입장: ''+v.toUpperCase()+'' (별도 화면)''):''코드를 입력하세요'';\u000a});\u000adocument.getElementById(''createBtn'').addEventListener(''click'',function(){\u000a  document.getElementById(''note'').textContent=''방 만들기 화면으로 이동 (별도 화면)'';\u000a});\u000a</script>\u000a</body></html>'),2,7,1783571880715);
INSERT INTO Wireframe VALUES('cmrd19jxx0009rwzi37be1wrt','cmrby3y0000001znnofoo0a53','방 생성','html',unistr('<!doctype html><html><head><meta charset="utf-8"><style>\u000a:root{--wf-bg:#f4f4f5;--wf-surface:#fff;--wf-line:#d4d4d8;--wf-ink:#3f3f46;--wf-muted:#a1a1aa;--wf-fill:#e4e4e7;--wf-radius:10px;--wf-gap:12px;}\u000a*{box-sizing:border-box;margin:0;padding:0}\u000abody{background:var(--wf-bg);color:var(--wf-ink);font-size:14px;line-height:1.5;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',sans-serif;display:flex;justify-content:center;padding:16px}\u000a.wf{position:relative;width:100%;max-width:390px;min-height:720px;background:var(--wf-surface);border:1px solid var(--wf-line);border-radius:20px;overflow:hidden;display:flex;flex-direction:column}\u000a.wf-topbar{display:flex;align-items:center;gap:8px;padding:14px 16px;border-bottom:1px solid var(--wf-line);font-weight:600}\u000a.wf-body{flex:1;padding:16px;display:flex;flex-direction:column;gap:16px;overflow:auto}\u000a.wf-sub{color:var(--wf-muted);font-size:13px}\u000a.wf-input{width:100%;border:1px solid var(--wf-line);border-radius:8px;padding:10px 12px;background:var(--wf-surface);font:inherit}\u000a.wf-btn{border:1px solid var(--wf-line);border-radius:8px;padding:10px 14px;background:var(--wf-surface);cursor:pointer;font:inherit}\u000a.wf-btn-primary{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.wf-field{display:flex;flex-direction:column;gap:6px}\u000a.wf-label{font-size:13px;font-weight:600}\u000a.chips{display:flex;gap:8px;flex-wrap:wrap}\u000a.chip{border:1px solid var(--wf-line);border-radius:8px;padding:9px 12px;background:var(--wf-surface);cursor:pointer;font:inherit;font-size:13px;color:var(--wf-muted)}\u000a.chip.on{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.frow{display:flex;align-items:center;gap:10px}\u000a.picker{width:100%;border:1px solid var(--wf-line);border-radius:8px;padding:10px 12px;background:var(--wf-surface);font:inherit;cursor:pointer;display:flex;align-items:center;justify-content:space-between;color:var(--wf-muted);text-align:left}\u000a.picker.set{color:var(--wf-ink);font-weight:600}\u000a/* 슬라이더 */\u000ainput[type=range]{-webkit-appearance:none;appearance:none;height:6px;background:var(--wf-fill);border-radius:999px;outline:none}\u000ainput[type=range]::-webkit-slider-thumb{-webkit-appearance:none;width:18px;height:18px;border-radius:50%;background:var(--wf-ink);border:2px solid #fff;box-shadow:0 0 0 1px var(--wf-line);cursor:pointer}\u000ainput[type=range]::-moz-range-thumb{width:18px;height:18px;border-radius:50%;background:var(--wf-ink);border:2px solid #fff;cursor:pointer}\u000a/* 스텝퍼 */\u000a.step{width:44px;height:44px;border:1px solid var(--wf-line);border-radius:8px;background:var(--wf-surface);cursor:pointer;font-size:18px}\u000a/* 모달 + 캘린더 */\u000a.modal{position:absolute;inset:0;background:rgba(0,0,0,.35);display:none;align-items:flex-end;justify-content:center}\u000a.modal.show{display:flex}\u000a.sheet{background:var(--wf-surface);width:100%;border-radius:16px 16px 0 0;padding:18px 16px 24px;display:flex;flex-direction:column;gap:12px}\u000a.cal-head{display:flex;align-items:center;justify-content:space-between}\u000a.cal-head button{border:none;background:none;font-size:20px;cursor:pointer;padding:4px 12px;color:var(--wf-ink)}\u000a.cal-grid{display:grid;grid-template-columns:repeat(7,1fr);gap:4px}\u000a.cal-dow{text-align:center;font-size:11px;color:var(--wf-muted);padding:4px 0}\u000a.cal-day{border:none;background:none;padding:9px 0;border-radius:8px;cursor:pointer;font:inherit;color:var(--wf-ink)}\u000a.cal-day:hover{background:var(--wf-fill)}\u000a.cal-day.sel{background:var(--wf-ink);color:#fff}\u000a.time-row{display:flex;align-items:center;gap:8px}\u000a.time-row select{border:1px solid var(--wf-line);border-radius:8px;padding:8px 10px;background:var(--wf-surface);font:inherit}\u000a</style></head>\u000a<body data-screen="room-create">\u000a<div class="wf">\u000a <header class="wf-topbar">← 방 만들기</header>\u000a <main class="wf-body">\u000a   <div class="wf-field">\u000a     <span class="wf-label">방 제목</span>\u000a     <input class="wf-input" placeholder="예: 아침 3km 대결">\u000a   </div>\u000a\u000a   <!-- 목표 거리 (프리셋 + 직접 입력) -->\u000a   <div class="wf-field">\u000a     <span class="wf-label">목표 거리</span>\u000a     <div class="chips" id="distChips">\u000a       <button type="button" class="chip" data-v="2">2km</button>\u000a       <button type="button" class="chip on" data-v="3">3km</button>\u000a       <button type="button" class="chip" data-v="5">5km</button>\u000a       <button type="button" class="chip" data-v="10">10km</button>\u000a       <button type="button" class="chip" id="distCustomChip">직접 입력</button>\u000a     </div>\u000a     <div id="distCustomWrap" style="display:none">\u000a       <div class="frow"><input class="wf-input" id="distCustom" type="number" min="0.5" step="0.5" placeholder="예: 7" style="flex:1"><span class="wf-label">km</span></div>\u000a     </div>\u000a     <span class="wf-sub" id="distSummary">목표 거리: 3km</span>\u000a   </div>\u000a\u000a   <!-- 시작 시간 (캘린더 피커) -->\u000a   <div class="wf-field">\u000a     <span class="wf-label">시작 시간</span>\u000a     <button type="button" class="picker" id="startPicker">\u000a       <span id="startText">날짜·시간을 선택하세요</span>\u000a       <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><rect x="3" y="4" width="18" height="17" rx="2"/><line x1="3" y1="9" x2="21" y2="9"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="16" y1="2" x2="16" y2="6"/></svg>\u000a     </button>\u000a   </div>\u000a\u000a   <!-- 제한 시간 (슬라이더 + 직접 입력) -->\u000a   <div class="wf-field">\u000a     <span class="wf-label">제한 시간 (분)</span>\u000a     <div class="frow">\u000a       <input type="range" id="limitRange" min="5" max="120" step="5" value="30" style="flex:1">\u000a       <input class="wf-input" id="limitNum" type="number" min="5" max="120" value="30" style="width:78px;text-align:center">\u000a     </div>\u000a     <span class="wf-sub">5 ~ 120분 · 슬라이더 또는 직접 입력</span>\u000a   </div>\u000a\u000a   <!-- 최대 인원 -->\u000a   <div class="wf-field">\u000a     <span class="wf-label">최대 인원</span>\u000a     <div class="frow">\u000a       <button type="button" class="step" id="capMinus">−</button>\u000a       <b id="cap" style="font-size:18px;min-width:28px;text-align:center">6</b>\u000a       <button type="button" class="step" id="capPlus">+</button>\u000a       <span class="wf-sub">명</span>\u000a     </div>\u000a   </div>\u000a\u000a   <div style="flex:1"></div>\u000a   <button class="wf-btn wf-btn-primary" id="submit">방 개설</button>\u000a   <div id="note" class="wf-sub" style="text-align:center;min-height:16px"></div>\u000a </main>\u000a\u000a <!-- 날짜·시간 선택 모달 -->\u000a <div class="modal" id="dtModal">\u000a   <div class="sheet">\u000a     <b style="font-size:15px">시작 시간 선택</b>\u000a     <div class="cal-head"><button type="button" id="prevM">‹</button><span id="calTitle" style="font-weight:600"></span><button type="button" id="nextM">›</button></div>\u000a     <div class="cal-grid" id="calGrid"></div>\u000a     <div class="time-row" style="margin-top:6px">\u000a       <span class="wf-label">시간</span>\u000a       <select id="hh"></select><b>:</b><select id="mm"></select>\u000a     </div>\u000a     <div class="frow" style="margin-top:6px">\u000a       <button class="wf-btn" id="dtCancel" style="flex:1">취소</button>\u000a       <button class="wf-btn wf-btn-primary" id="dtOk" style="flex:1">확인</button>\u000a     </div>\u000a   </div>\u000a </div>\u000a</div>\u000a<script>\u000a// ---- 목표 거리 ----\u000avar distVal=3;\u000afunction setDistSummary(){document.getElementById(''distSummary'').textContent=''목표 거리: ''+distVal+''km'';}\u000adocument.querySelectorAll(''#distChips .chip[data-v]'').forEach(function(b){\u000a  b.addEventListener(''click'',function(){\u000a    document.querySelectorAll(''#distChips .chip'').forEach(function(x){x.classList.remove(''on'')});\u000a    this.classList.add(''on''); document.getElementById(''distCustomWrap'').style.display=''none'';\u000a    distVal=+this.getAttribute(''data-v''); setDistSummary();\u000a  });\u000a});\u000adocument.getElementById(''distCustomChip'').addEventListener(''click'',function(){\u000a  document.querySelectorAll(''#distChips .chip'').forEach(function(x){x.classList.remove(''on'')});\u000a  this.classList.add(''on'');\u000a  var w=document.getElementById(''distCustomWrap''); w.style.display=''block'';\u000a  var inp=document.getElementById(''distCustom''); inp.focus();\u000a});\u000adocument.getElementById(''distCustom'').addEventListener(''input'',function(){\u000a  var v=parseFloat(this.value); if(!isNaN(v)&&v>0){distVal=v; setDistSummary();}\u000a});\u000a\u000a// ---- 제한 시간 (슬라이더 <-> 입력 동기화) ----\u000avar range=document.getElementById(''limitRange''), num=document.getElementById(''limitNum'');\u000arange.addEventListener(''input'',function(){num.value=this.value;});\u000anum.addEventListener(''input'',function(){\u000a  var v=Math.max(5,Math.min(120,+this.value||5)); range.value=v;\u000a});\u000a\u000a// ---- 최대 인원 ----\u000avar cap=6;\u000adocument.getElementById(''capMinus'').addEventListener(''click'',function(){if(cap>2){cap--;document.getElementById(''cap'').textContent=cap;}});\u000adocument.getElementById(''capPlus'').addEventListener(''click'',function(){if(cap<20){cap++;document.getElementById(''cap'').textContent=cap;}});\u000a\u000a// ---- 캘린더 피커 ----\u000avar modal=document.getElementById(''dtModal'');\u000avar viewDate=new Date(); viewDate.setDate(1);\u000avar selDate=null;\u000afunction pad(n){return (n<10?''0'':'''')+n;}\u000afunction renderCal(){\u000a  var y=viewDate.getFullYear(), m=viewDate.getMonth();\u000a  document.getElementById(''calTitle'').textContent=y+''년 ''+(m+1)+''월'';\u000a  var startDow=new Date(y,m,1).getDay(), days=new Date(y,m+1,0).getDate();\u000a  var grid=document.getElementById(''calGrid''); grid.innerHTML='''';\u000a  [''일'',''월'',''화'',''수'',''목'',''금'',''토''].forEach(function(d){var e=document.createElement(''div'');e.className=''cal-dow'';e.textContent=d;grid.appendChild(e);});\u000a  for(var i=0;i<startDow;i++){grid.appendChild(document.createElement(''div''));}\u000a  for(var d=1;d<=days;d++){\u000a    var cell=document.createElement(''button'');cell.type=''button'';cell.className=''cal-day'';cell.textContent=d;\u000a    if(selDate && selDate.getFullYear()===y && selDate.getMonth()===m && selDate.getDate()===d) cell.classList.add(''sel'');\u000a    (function(dd){cell.addEventListener(''click'',function(){\u000a      selDate=new Date(y,m,dd);\u000a      [].forEach.call(grid.querySelectorAll(''.cal-day''),function(x){x.classList.remove(''sel'')});\u000a      this.classList.add(''sel'');\u000a    });})(d);\u000a    grid.appendChild(cell);\u000a  }\u000a}\u000a// 시/분 옵션\u000avar hh=document.getElementById(''hh''), mm=document.getElementById(''mm'');\u000afor(var h=0;h<24;h++){var o=document.createElement(''option'');o.value=h;o.textContent=pad(h);hh.appendChild(o);}\u000afor(var mi=0;mi<60;mi+=5){var o2=document.createElement(''option'');o2.value=mi;o2.textContent=pad(mi);mm.appendChild(o2);}\u000ahh.value=7; mm.value=0;\u000a\u000adocument.getElementById(''startPicker'').addEventListener(''click'',function(){renderCal();modal.classList.add(''show'');});\u000adocument.getElementById(''prevM'').addEventListener(''click'',function(){viewDate.setMonth(viewDate.getMonth()-1);renderCal();});\u000adocument.getElementById(''nextM'').addEventListener(''click'',function(){viewDate.setMonth(viewDate.getMonth()+1);renderCal();});\u000adocument.getElementById(''dtCancel'').addEventListener(''click'',function(){modal.classList.remove(''show'');});\u000adocument.getElementById(''dtOk'').addEventListener(''click'',function(){\u000a  if(!selDate){document.getElementById(''note'').textContent=''날짜를 선택하세요'';modal.classList.remove(''show'');return;}\u000a  var dows=[''일'',''월'',''화'',''수'',''목'',''금'',''토''];\u000a  var txt=selDate.getFullYear()+''-''+pad(selDate.getMonth()+1)+''-''+pad(selDate.getDate())+'' (''+dows[selDate.getDay()]+'') ''+pad(+hh.value)+'':''+pad(+mm.value);\u000a  var el=document.getElementById(''startText''); el.textContent=txt; el.parentElement.classList.add(''set'');\u000a  modal.classList.remove(''show'');\u000a});\u000a\u000adocument.getElementById(''submit'').addEventListener(''click'',function(){\u000a  document.getElementById(''note'').textContent=''방 개설 (대기실로 이동 · 별도 화면)'';\u000a});\u000a</script>\u000a</body></html>'),3,2,1783572918837);
INSERT INTO Wireframe VALUES('cmrd1di6n000brwzid0rvx7p9','cmrby3y0000001znnofoo0a53','방 생성','html',unistr('<!doctype html><html><head><meta charset="utf-8"><style>\u000a:root{--wf-bg:#f4f4f5;--wf-surface:#fff;--wf-line:#d4d4d8;--wf-ink:#3f3f46;--wf-muted:#a1a1aa;--wf-fill:#e4e4e7;--wf-radius:10px;--wf-gap:12px;}\u000a*{box-sizing:border-box;margin:0;padding:0}\u000abody{background:var(--wf-bg);color:var(--wf-ink);font-size:14px;line-height:1.5;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',sans-serif;display:flex;justify-content:center;padding:16px}\u000a.wf{position:relative;width:100%;max-width:390px;min-height:720px;background:var(--wf-surface);border:1px solid var(--wf-line);border-radius:20px;overflow:hidden;display:flex;flex-direction:column}\u000a.wf-topbar{display:flex;align-items:center;gap:8px;padding:14px 16px;border-bottom:1px solid var(--wf-line);font-weight:600}\u000a.wf-body{flex:1;padding:16px;display:flex;flex-direction:column;gap:16px;overflow:auto}\u000a.wf-sub{color:var(--wf-muted);font-size:13px}\u000a.wf-input{width:100%;border:1px solid var(--wf-line);border-radius:8px;padding:10px 12px;background:var(--wf-surface);font:inherit}\u000a.wf-btn{border:1px solid var(--wf-line);border-radius:8px;padding:10px 14px;background:var(--wf-surface);cursor:pointer;font:inherit}\u000a.wf-btn-primary{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.wf-field{display:flex;flex-direction:column;gap:6px}\u000a.wf-label{font-size:13px;font-weight:600}\u000a.chips{display:flex;gap:8px;flex-wrap:wrap}\u000a.chip{border:1px solid var(--wf-line);border-radius:8px;padding:9px 12px;background:var(--wf-surface);cursor:pointer;font:inherit;font-size:13px;color:var(--wf-muted)}\u000a.chip.on{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.frow{display:flex;align-items:center;gap:10px}\u000a.picker{width:100%;border:1px solid var(--wf-line);border-radius:8px;padding:10px 12px;background:var(--wf-surface);font:inherit;cursor:pointer;display:flex;align-items:center;justify-content:space-between;color:var(--wf-muted);text-align:left}\u000a.picker.set{color:var(--wf-ink);font-weight:600}\u000a/* 슬라이더 */\u000ainput[type=range]{-webkit-appearance:none;appearance:none;height:6px;background:var(--wf-fill);border-radius:999px;outline:none}\u000ainput[type=range]::-webkit-slider-thumb{-webkit-appearance:none;width:18px;height:18px;border-radius:50%;background:var(--wf-ink);border:2px solid #fff;box-shadow:0 0 0 1px var(--wf-line);cursor:pointer}\u000ainput[type=range]::-moz-range-thumb{width:18px;height:18px;border-radius:50%;background:var(--wf-ink);border:2px solid #fff;cursor:pointer}\u000a/* 스텝퍼 */\u000a.step{width:44px;height:44px;border:1px solid var(--wf-line);border-radius:8px;background:var(--wf-surface);cursor:pointer;font-size:18px}\u000a/* 모달 + 캘린더 */\u000a.modal{position:absolute;inset:0;background:rgba(0,0,0,.35);display:none;align-items:flex-end;justify-content:center}\u000a.modal.show{display:flex}\u000a.sheet{background:var(--wf-surface);width:100%;border-radius:16px 16px 0 0;padding:18px 16px 24px;display:flex;flex-direction:column;gap:12px}\u000a.cal-head{display:flex;align-items:center;justify-content:space-between}\u000a.cal-head button{border:none;background:none;font-size:20px;cursor:pointer;padding:4px 12px;color:var(--wf-ink)}\u000a.cal-grid{display:grid;grid-template-columns:repeat(7,1fr);gap:4px}\u000a.cal-dow{text-align:center;font-size:11px;color:var(--wf-muted);padding:4px 0}\u000a.cal-day{border:none;background:none;padding:9px 0;border-radius:8px;cursor:pointer;font:inherit;color:var(--wf-ink)}\u000a.cal-day:hover{background:var(--wf-fill)}\u000a.cal-day.sel{background:var(--wf-ink);color:#fff}\u000a.time-row{display:flex;align-items:center;gap:8px}\u000a.time-row select{border:1px solid var(--wf-line);border-radius:8px;padding:8px 10px;background:var(--wf-surface);font:inherit}\u000a</style></head>\u000a<body data-screen="room-create">\u000a<div class="wf">\u000a <header class="wf-topbar">← 방 만들기</header>\u000a <main class="wf-body">\u000a   <div class="wf-field">\u000a     <span class="wf-label">방 제목</span>\u000a     <input class="wf-input" placeholder="예: 아침 3km 대결">\u000a   </div>\u000a\u000a   <!-- 목표 거리 (프리셋 + 직접 입력) -->\u000a   <div class="wf-field">\u000a     <span class="wf-label">목표 거리</span>\u000a     <div class="chips" id="distChips">\u000a       <button type="button" class="chip" data-v="2">2km</button>\u000a       <button type="button" class="chip on" data-v="3">3km</button>\u000a       <button type="button" class="chip" data-v="5">5km</button>\u000a       <button type="button" class="chip" data-v="10">10km</button>\u000a       <button type="button" class="chip" id="distCustomChip">직접 입력</button>\u000a     </div>\u000a     <div id="distCustomWrap" style="display:none">\u000a       <div class="frow"><input class="wf-input" id="distCustom" type="number" min="0.5" step="0.5" placeholder="예: 7" style="flex:1"><span class="wf-label">km</span></div>\u000a     </div>\u000a     <span class="wf-sub" id="distSummary">목표 거리: 3km</span>\u000a   </div>\u000a\u000a   <!-- 제한 시간 (슬라이더 + 직접 입력) -->\u000a   <div class="wf-field">\u000a     <span class="wf-label">제한 시간 (분)</span>\u000a     <div class="frow">\u000a       <input type="range" id="limitRange" min="5" max="120" step="5" value="30" style="flex:1">\u000a       <input class="wf-input" id="limitNum" type="number" min="5" max="120" value="30" style="width:78px;text-align:center">\u000a     </div>\u000a     <span class="wf-sub">5 ~ 120분 · 슬라이더 또는 직접 입력</span>\u000a   </div>\u000a\u000a   <!-- 시작 시간 (캘린더 피커) -->\u000a   <div class="wf-field">\u000a     <span class="wf-label">시작 시간</span>\u000a     <button type="button" class="picker" id="startPicker">\u000a       <span id="startText">날짜·시간을 선택하세요</span>\u000a       <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><rect x="3" y="4" width="18" height="17" rx="2"/><line x1="3" y1="9" x2="21" y2="9"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="16" y1="2" x2="16" y2="6"/></svg>\u000a     </button>\u000a   </div>\u000a\u000a   <!-- 최대 인원 -->\u000a   <div class="wf-field">\u000a     <span class="wf-label">최대 인원</span>\u000a     <div class="frow">\u000a       <button type="button" class="step" id="capMinus">−</button>\u000a       <b id="cap" style="font-size:18px;min-width:28px;text-align:center">6</b>\u000a       <button type="button" class="step" id="capPlus">+</button>\u000a       <span class="wf-sub">명</span>\u000a     </div>\u000a   </div>\u000a\u000a   <div style="flex:1"></div>\u000a   <button class="wf-btn wf-btn-primary" id="submit">방 개설</button>\u000a   <div id="note" class="wf-sub" style="text-align:center;min-height:16px"></div>\u000a </main>\u000a\u000a <!-- 날짜·시간 선택 모달 -->\u000a <div class="modal" id="dtModal">\u000a   <div class="sheet">\u000a     <b style="font-size:15px">시작 시간 선택</b>\u000a     <div class="cal-head"><button type="button" id="prevM">‹</button><span id="calTitle" style="font-weight:600"></span><button type="button" id="nextM">›</button></div>\u000a     <div class="cal-grid" id="calGrid"></div>\u000a     <div class="time-row" style="margin-top:6px">\u000a       <span class="wf-label">시간</span>\u000a       <select id="hh"></select><b>:</b><select id="mm"></select>\u000a     </div>\u000a     <div class="frow" style="margin-top:6px">\u000a       <button class="wf-btn" id="dtCancel" style="flex:1">취소</button>\u000a       <button class="wf-btn wf-btn-primary" id="dtOk" style="flex:1">확인</button>\u000a     </div>\u000a   </div>\u000a </div>\u000a</div>\u000a<script>\u000a// ---- 목표 거리 ----\u000avar distVal=3;\u000afunction setDistSummary(){document.getElementById(''distSummary'').textContent=''목표 거리: ''+distVal+''km'';}\u000adocument.querySelectorAll(''#distChips .chip[data-v]'').forEach(function(b){\u000a  b.addEventListener(''click'',function(){\u000a    document.querySelectorAll(''#distChips .chip'').forEach(function(x){x.classList.remove(''on'')});\u000a    this.classList.add(''on''); document.getElementById(''distCustomWrap'').style.display=''none'';\u000a    distVal=+this.getAttribute(''data-v''); setDistSummary();\u000a  });\u000a});\u000adocument.getElementById(''distCustomChip'').addEventListener(''click'',function(){\u000a  document.querySelectorAll(''#distChips .chip'').forEach(function(x){x.classList.remove(''on'')});\u000a  this.classList.add(''on'');\u000a  document.getElementById(''distCustomWrap'').style.display=''block'';\u000a  document.getElementById(''distCustom'').focus();\u000a});\u000adocument.getElementById(''distCustom'').addEventListener(''input'',function(){\u000a  var v=parseFloat(this.value); if(!isNaN(v)&&v>0){distVal=v; setDistSummary();}\u000a});\u000a\u000a// ---- 제한 시간 (슬라이더 <-> 입력 동기화) ----\u000avar range=document.getElementById(''limitRange''), num=document.getElementById(''limitNum'');\u000arange.addEventListener(''input'',function(){num.value=this.value;});\u000anum.addEventListener(''input'',function(){var v=Math.max(5,Math.min(120,+this.value||5)); range.value=v;});\u000a\u000a// ---- 최대 인원 ----\u000avar cap=6;\u000adocument.getElementById(''capMinus'').addEventListener(''click'',function(){if(cap>2){cap--;document.getElementById(''cap'').textContent=cap;}});\u000adocument.getElementById(''capPlus'').addEventListener(''click'',function(){if(cap<20){cap++;document.getElementById(''cap'').textContent=cap;}});\u000a\u000a// ---- 캘린더 피커 ----\u000avar modal=document.getElementById(''dtModal'');\u000avar viewDate=new Date(); viewDate.setDate(1);\u000avar selDate=null;\u000afunction pad(n){return (n<10?''0'':'''')+n;}\u000afunction renderCal(){\u000a  var y=viewDate.getFullYear(), m=viewDate.getMonth();\u000a  document.getElementById(''calTitle'').textContent=y+''년 ''+(m+1)+''월'';\u000a  var startDow=new Date(y,m,1).getDay(), days=new Date(y,m+1,0).getDate();\u000a  var grid=document.getElementById(''calGrid''); grid.innerHTML='''';\u000a  [''일'',''월'',''화'',''수'',''목'',''금'',''토''].forEach(function(d){var e=document.createElement(''div'');e.className=''cal-dow'';e.textContent=d;grid.appendChild(e);});\u000a  for(var i=0;i<startDow;i++){grid.appendChild(document.createElement(''div''));}\u000a  for(var d=1;d<=days;d++){\u000a    var cell=document.createElement(''button'');cell.type=''button'';cell.className=''cal-day'';cell.textContent=d;\u000a    if(selDate && selDate.getFullYear()===y && selDate.getMonth()===m && selDate.getDate()===d) cell.classList.add(''sel'');\u000a    (function(dd){cell.addEventListener(''click'',function(){\u000a      selDate=new Date(y,m,dd);\u000a      [].forEach.call(grid.querySelectorAll(''.cal-day''),function(x){x.classList.remove(''sel'')});\u000a      this.classList.add(''sel'');\u000a    });})(d);\u000a    grid.appendChild(cell);\u000a  }\u000a}\u000avar hh=document.getElementById(''hh''), mm=document.getElementById(''mm'');\u000afor(var h=0;h<24;h++){var o=document.createElement(''option'');o.value=h;o.textContent=pad(h);hh.appendChild(o);}\u000afor(var mi=0;mi<60;mi+=5){var o2=document.createElement(''option'');o2.value=mi;o2.textContent=pad(mi);mm.appendChild(o2);}\u000ahh.value=7; mm.value=0;\u000a\u000adocument.getElementById(''startPicker'').addEventListener(''click'',function(){renderCal();modal.classList.add(''show'');});\u000adocument.getElementById(''prevM'').addEventListener(''click'',function(){viewDate.setMonth(viewDate.getMonth()-1);renderCal();});\u000adocument.getElementById(''nextM'').addEventListener(''click'',function(){viewDate.setMonth(viewDate.getMonth()+1);renderCal();});\u000adocument.getElementById(''dtCancel'').addEventListener(''click'',function(){modal.classList.remove(''show'');});\u000adocument.getElementById(''dtOk'').addEventListener(''click'',function(){\u000a  if(!selDate){document.getElementById(''note'').textContent=''날짜를 선택하세요'';modal.classList.remove(''show'');return;}\u000a  var dows=[''일'',''월'',''화'',''수'',''목'',''금'',''토''];\u000a  var txt=selDate.getFullYear()+''-''+pad(selDate.getMonth()+1)+''-''+pad(selDate.getDate())+'' (''+dows[selDate.getDay()]+'') ''+pad(+hh.value)+'':''+pad(+mm.value);\u000a  var el=document.getElementById(''startText''); el.textContent=txt; el.parentElement.classList.add(''set'');\u000a  modal.classList.remove(''show'');\u000a});\u000a\u000adocument.getElementById(''submit'').addEventListener(''click'',function(){\u000a  document.getElementById(''note'').textContent=''방 개설 (대기실로 이동 · 별도 화면)'';\u000a});\u000a</script>\u000a</body></html>'),3,3,1783573103183);
INSERT INTO Wireframe VALUES('cmrd2my2e000drwzi06yz9t18','cmrby3y0000001znnofoo0a53','대기실','html',unistr('<!doctype html><html><head><meta charset="utf-8"><style>\u000a:root{--wf-bg:#f4f4f5;--wf-surface:#fff;--wf-line:#d4d4d8;--wf-ink:#3f3f46;--wf-muted:#a1a1aa;--wf-fill:#e4e4e7;--wf-radius:10px;--wf-gap:12px;}\u000a*{box-sizing:border-box;margin:0;padding:0}\u000abody{background:var(--wf-bg);color:var(--wf-ink);font-size:14px;line-height:1.5;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',sans-serif;display:flex;justify-content:center;padding:16px}\u000a.wf{width:100%;max-width:390px;min-height:720px;background:var(--wf-surface);border:1px solid var(--wf-line);border-radius:20px;overflow:hidden;display:flex;flex-direction:column}\u000a.wf-topbar{display:flex;align-items:center;gap:8px;padding:14px 16px;border-bottom:1px solid var(--wf-line);font-weight:600}\u000a.wf-body{flex:1;padding:16px;display:flex;flex-direction:column;gap:var(--wf-gap);overflow:auto}\u000a.wf-title{font-size:18px;font-weight:700}\u000a.wf-sub{color:var(--wf-muted);font-size:13px}\u000a.wf-card{border:1px solid var(--wf-line);border-radius:var(--wf-radius);padding:14px}\u000a.wf-input{width:100%;border:1px solid var(--wf-line);border-radius:8px;padding:10px 12px;background:var(--wf-surface);font:inherit}\u000a.wf-btn{border:1px solid var(--wf-line);border-radius:8px;padding:10px 14px;background:var(--wf-surface);cursor:pointer;font:inherit}\u000a.wf-btn-primary{background:var(--wf-ink);color:#fff;border-color:var(--wf-ink)}\u000a.wf-avatar{flex:0 0 auto;width:36px;height:36px;border-radius:50%;background:var(--wf-fill)}\u000a.wf-badge{font-size:11px;padding:2px 8px;border-radius:999px;background:var(--wf-fill);color:var(--wf-muted)}\u000a.wf-label{font-size:13px;font-weight:600}\u000a.stats{display:flex;gap:8px}\u000a.stat{flex:1;border:1px solid var(--wf-line);border-radius:var(--wf-radius);padding:10px;text-align:center}\u000a.stat b{display:block;font-size:16px}\u000a.efield{display:flex;align-items:center;justify-content:space-between;gap:8px;margin-bottom:8px}\u000a.efield input{width:110px;text-align:right}\u000a/* 참가자 그리드 */\u000a.pgrid{display:grid;grid-template-columns:repeat(3,1fr);gap:10px}\u000a.ptile{border:1px solid var(--wf-line);border-radius:var(--wf-radius);padding:12px 8px;min-height:108px;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:6px;text-align:center}\u000a.ptile .wf-avatar{width:44px;height:44px}\u000a.pname{font-size:13px;font-weight:600}\u000a.ptile .kick{padding:3px 10px;font-size:11px}\u000a.host-tag{font-size:10px;font-weight:700;padding:2px 8px;border-radius:999px;background:var(--wf-ink);color:#fff}\u000a.ptile.empty{border-style:dashed;color:var(--wf-muted)}\u000a</style></head>\u000a<body data-screen="waiting-room">\u000a<div class="wf">\u000a <header class="wf-topbar">← 대기실</header>\u000a <main class="wf-body">\u000a   <div style="display:flex;justify-content:space-between;align-items:center">\u000a     <div class="wf-title">아침 3km 대결</div><span class="wf-badge">모집 중</span>\u000a   </div>\u000a   <div class="wf-card" style="text-align:center">\u000a     <div class="wf-sub">시작까지</div>\u000a     <div style="font-size:28px;font-weight:700" id="cd">09:58</div>\u000a   </div>\u000a   <div class="stats">\u000a     <div class="stat"><span class="wf-sub">목표 거리</span><b id="sGoal">3.0km</b></div>\u000a     <div class="stat"><span class="wf-sub">제한 시간</span><b id="sLimit">30분</b></div>\u000a     <div class="stat"><span class="wf-sub">완주 기준 페이스</span><b id="sPace">10''00"</b><span class="wf-sub">/km</span></div>\u000a   </div>\u000a   <div style="display:flex;justify-content:space-between;align-items:center">\u000a     <span class="wf-label">참가자</span><span class="wf-sub" id="count">3 / 6</span>\u000a   </div>\u000a   <div class="pgrid" id="pgrid">\u000a     <div class="ptile filled"><div class="wf-avatar"></div><span class="pname">나</span><span class="host-tag">방장</span></div>\u000a     <div class="ptile filled"><div class="wf-avatar"></div><span class="pname">러너_김</span><button type="button" class="wf-btn kick">강퇴</button></div>\u000a     <div class="ptile filled"><div class="wf-avatar"></div><span class="pname">러너_이</span><button type="button" class="wf-btn kick">강퇴</button></div>\u000a     <div class="ptile empty"><span class="wf-sub">빈 자리</span></div>\u000a     <div class="ptile empty"><span class="wf-sub">빈 자리</span></div>\u000a     <div class="ptile empty"><span class="wf-sub">빈 자리</span></div>\u000a   </div>\u000a   <button class="wf-btn" id="editToggle">조건 수정 (방장)</button>\u000a   <div class="wf-card" id="editBox" style="display:none">\u000a     <div class="wf-label" style="margin-bottom:8px">조건 수정 — 모집 중에만 가능</div>\u000a     <div class="efield"><span>목표 거리 (km)</span><input class="wf-input" id="eGoal" type="number" step="0.5" value="3"></div>\u000a     <div class="efield"><span>제한 시간 (분)</span><input class="wf-input" id="eLimit" type="number" value="30"></div>\u000a     <div class="efield"><span>최대 인원</span><input class="wf-input" id="eCap" type="number" value="6"></div>\u000a     <div class="wf-sub">→ 완주 기준 페이스 <b id="ePace">10''00"</b>/km</div>\u000a   </div>\u000a   <div style="flex:1"></div>\u000a   <button class="wf-btn wf-btn-primary" disabled style="opacity:.6">시작 시간에 자동 시작</button>\u000a </main>\u000a</div>\u000a<script>\u000afunction pad(n){return (n<10?''0'':'''')+n;}\u000a// 완주 기준 페이스 = 제한시간 / 목표거리 → 분:초 per km\u000afunction pace(goalKm,limitMin){\u000a  if(!goalKm||goalKm<=0) return "--''--\\"";\u000a  var sec=Math.round(limitMin*60/goalKm);\u000a  return Math.floor(sec/60)+"''"+pad(sec%60)+''"'';\u000a}\u000afunction applyTop(goalKm,limitMin){\u000a  document.getElementById(''sGoal'').textContent=goalKm.toFixed(1)+''km'';\u000a  document.getElementById(''sLimit'').textContent=limitMin+''분'';\u000a  document.getElementById(''sPace'').textContent=pace(goalKm,limitMin);\u000a}\u000aapplyTop(3,30);\u000a\u000a// 카운트다운\u000avar t=598,cd=document.getElementById(''cd'');\u000asetInterval(function(){ if(t>0){t--; cd.textContent=pad(Math.floor(t/60))+'':''+pad(t%60);} },1000);\u000a\u000a// 강퇴 → 빈 자리로 전환\u000afunction refresh(){ document.getElementById(''count'').textContent=document.querySelectorAll(''#pgrid .ptile.filled'').length+'' / ''+(document.getElementById(''eCap'').value||6); }\u000afunction bindKick(b){ b.addEventListener(''click'',function(){ var tile=b.closest(''.ptile''); tile.className=''ptile empty''; tile.innerHTML=''<span class="wf-sub">빈 자리</span>''; refresh(); }); }\u000adocument.querySelectorAll(''.kick'').forEach(bindKick);\u000a\u000a// 조건 수정 → 페이스 실시간 재계산\u000adocument.getElementById(''editToggle'').addEventListener(''click'',function(){\u000a  var e=document.getElementById(''editBox''); var open=e.style.display===''none'';\u000a  e.style.display=open?''block'':''none''; this.classList.toggle(''wf-btn-primary'',open);\u000a});\u000afunction recalc(){\u000a  var g=parseFloat(document.getElementById(''eGoal'').value),l=parseFloat(document.getElementById(''eLimit'').value);\u000a  document.getElementById(''ePace'').textContent=pace(g,l);\u000a  if(g>0&&l>0) applyTop(g,l);\u000a  refresh();\u000a}\u000a[''eGoal'',''eLimit'',''eCap''].forEach(function(id){ document.getElementById(id).addEventListener(''input'',recalc); });\u000a</script>\u000a</body></html>'),4,3,1783575223285);
